import { Client, Campaign, AdSet, Ad, Metrics, Creative, DemographicData, VideoMetrics } from "../types";

export interface MetaAccountInfo {
  id: string;
  name: string;
  currency: string;
}

const getActionValue = (actions: any[], actionType: string): number => {
  if (!actions || !Array.isArray(actions)) return 0;
  const action = actions.find((a: any) => a.action_type === actionType);
  return action ? parseFloat(action.value || action.count || 0) : 0;
};

// Mapeia os presets do nosso app para os presets da API da Meta
const mapDatePreset = (preset: string): string => {
  const mapping: Record<string, string> = {
    'maximum': 'maximum',
    'today': 'today',
    'yesterday': 'yesterday',
    'today_and_yesterday': 'today', // Meta não tem esse exato, usamos today como base ou custom (simplificando aqui)
    'last_7d': 'last_7d',
    'last_14d': 'last_14d',
    'last_28d': 'last_28d',
    'last_30d': 'last_30d',
    'this_week': 'this_week',
    'last_week': 'last_week',
    'this_month': 'this_month',
    'last_month': 'last_month',
    'custom': 'maximum' // Default para custom se não implementado
  };
  return mapping[preset] || 'this_month';
};

const mapInsightsToMetrics = (insightsData: any): Metrics => {
  const insights = insightsData?.data?.[0] || {};
  const actions = insights.actions || [];

  const messages = getActionValue(actions, 'onsite_conversion.messaging_first_reply');
  const spend = parseFloat(insights.spend || 0);

  const video: VideoMetrics = {
    plays: getActionValue(actions, 'video_play'),
    avgTime: parseFloat(insights.video_avg_time_watched_actions?.[0]?.value || 0),
    retention25: getActionValue(actions, 'video_p25_watched_actions'),
    retention50: getActionValue(actions, 'video_p50_watched_actions'),
    retention75: getActionValue(actions, 'video_p75_watched_actions'),
    retention100: getActionValue(actions, 'video_p100_watched_actions'),
  };

  return {
    spend,
    impressions: parseInt(insights.impressions || 0),
    reach: parseInt(insights.reach || 0),
    frequency: parseFloat(insights.frequency || 0),
    cpm: parseFloat(insights.cpm || 0),
    clicks: parseInt(insights.clicks || 0),
    conversions: getActionValue(actions, 'purchase'),
    conversionValue: getActionValue(insights.action_values, 'purchase'),
    messages,
    costPerMessage: messages > 0 ? spend / messages : 0,
    video: video.plays > 0 ? video : undefined
  };
};

export const validateMetaConnection = async (adAccountId: string, accessToken: string): Promise<MetaAccountInfo> => {
  const cleanActId = adAccountId.replace('act_', '').trim();
  const url = `https://graph.facebook.com/v19.0/act_${cleanActId}?fields=name,currency&access_token=${accessToken}`;
  const response = await fetch(url);
  const json = await response.json();
  if (json.error) throw new Error(json.error.message);
  return { id: json.id, name: json.name, currency: json.currency };
};

export const syncMetaAdsData = async (client: Client, datePreset: string = 'this_month'): Promise<Client> => {
  if (!client.adAccountId || !client.accessToken) throw new Error("Credenciais ausentes.");

  const metaPreset = mapDatePreset(datePreset);
  const accountId = client.adAccountId.startsWith('act_') ? client.adAccountId : `act_${client.adAccountId}`;
  const token = client.accessToken;

  // Garantimos que o date_preset seja passado para as sub-consultas de insights
  const insightsFields = `spend,impressions,reach,frequency,cpm,clicks,actions,action_values,video_avg_time_watched_actions`;
  const insightsParams = `.date_preset(${metaPreset})`;

  try {
    const url = `https://graph.facebook.com/v19.0/${accountId}/campaigns?fields=id,name,status,objective,daily_budget,lifetime_budget,start_time,stop_time,insights${insightsParams}{${insightsFields}},adsets{id,name,status,daily_budget,lifetime_budget,targeting,insights${insightsParams}{${insightsFields}},ads{id,name,status,creative{id,title,image_url,thumbnail_url},insights${insightsParams}{${insightsFields}}}}&date_preset=${metaPreset}&access_token=${token}`;

    const response = await fetch(url);
    const json = await response.json();
    if (json.error) throw new Error(json.error.message);

    const campaigns: Campaign[] = await Promise.all(json.data.map(async (fbCamp: any) => {
      const demoUrl = `https://graph.facebook.com/v19.0/${fbCamp.id}/insights?breakdowns=age,gender&fields=spend,actions&date_preset=${metaPreset}&access_token=${token}`;
      const demoRes = await fetch(demoUrl);
      const demoJson = await demoRes.json();

      const demographics: DemographicData[] = (demoJson.data || []).map((d: any) => ({
        age: d.age,
        gender: d.gender,
        spend: parseFloat(d.spend || 0),
        results: getActionValue(d.actions, fbCamp.objective === 'MESSAGES' ? 'onsite_conversion.messaging_first_reply' : 'purchase')
      }));

      const campMetrics = { ...mapInsightsToMetrics(fbCamp.insights), demographics };

      const adSets: AdSet[] = (fbCamp.adsets?.data || []).map((fbAdSet: any) => {
        const ads: Ad[] = (fbAdSet.ads?.data || []).map((fbAd: any) => ({
          id: fbAd.id,
          name: fbAd.name,
          status: fbAd.status === 'ACTIVE' ? 'active' : 'paused',
          creative: {
            id: fbAd.creative?.id || '0',
            type: 'image',
            url: fbAd.creative?.image_url || fbAd.creative?.thumbnail_url || 'https://via.placeholder.com/150',
            headline: fbAd.creative?.title || fbAd.name
          },
          metrics: mapInsightsToMetrics(fbAd.insights)
        }));

        return {
          id: fbAdSet.id,
          name: fbAdSet.name,
          status: fbAdSet.status === 'ACTIVE' ? 'active' : 'paused',
          budget: parseFloat(fbAdSet.daily_budget || fbAdSet.lifetime_budget || 0) / 100,
          budgetType: fbAdSet.daily_budget ? 'DAILY' : 'LIFETIME',
          audience: JSON.stringify(fbAdSet.targeting),
          metrics: mapInsightsToMetrics(fbAdSet.insights),
          ads
        };
      });

      return {
        id: fbCamp.id,
        name: fbCamp.name,
        status: fbCamp.status === 'ACTIVE' ? 'active' : 'paused',
        platform: 'facebook',
        objective: fbCamp.objective,
        metrics: campMetrics,
        budget: parseFloat(fbCamp.daily_budget || fbCamp.lifetime_budget || 0) / 100,
        budgetType: fbCamp.daily_budget ? 'DAILY' : 'LIFETIME',
        startTime: fbCamp.start_time,
        endTime: fbCamp.stop_time,
        adSets,
        creative: adSets[0]?.ads[0]?.creative || { id: '0', type: 'image', url: '', headline: '' },
        audience: 'Múltiplos Públicos'
      };
    }));

    return { ...client, lastSync: new Date().toLocaleTimeString(), campaigns };
  } catch (e: any) {
    throw e;
  }
};

import React, { useState, useMemo, useEffect } from 'react';
import { MOCK_CLIENTS } from './constants';
import { Sidebar } from './components/Sidebar';
import { StatCard } from './components/StatCard';
import { CampaignDetails } from './components/CampaignDetails';
import { SettingsModal } from './components/SettingsModal';
import { DateRangePicker, DatePreset } from './components/DateRangePicker';
import { Client, Campaign } from './types';
import { Search, Filter, Calendar, BarChart2, DollarSign, MousePointer, ShoppingBag, Eye, Target, RefreshCw, AlertTriangle, Menu, TrendingUp, Loader2 } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { syncMetaAdsData, MetaAccountInfo } from './services/metaService';

function App() {
  const [clients, setClients] = useState<Client[]>(MOCK_CLIENTS);
  const [selectedClientId, setSelectedClientId] = useState<string>(MOCK_CLIENTS[0].id);
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);

  const [datePreset, setDatePreset] = useState<DatePreset>('this_month');
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [editingClient, setEditingClient] = useState<Client | null>(null);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const selectedClient = clients.find(c => c.id === selectedClientId) || clients[0];

  const clientMetrics = useMemo(() => {
    if (!selectedClient) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend;
      acc.impressions += curr.metrics.impressions;
      acc.clicks += curr.metrics.clicks;
      acc.conversions += curr.metrics.conversions;
      acc.revenue += curr.metrics.conversionValue;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';
  const ctr = clientMetrics.impressions > 0 ? ((clientMetrics.clicks / clientMetrics.impressions) * 100).toFixed(2) : '0.00';

  // Gerar dados de gráfico dinâmicos baseados nas métricas atuais para simular atualização visual
  const chartData = useMemo(() => {
    const isMax = datePreset === 'maximum';
    const multiplier = isMax ? 2.5 : 1;
    return [
      { name: 'Ponto 1', spend: (clientMetrics.spend * 0.1) * multiplier, revenue: (clientMetrics.revenue * 0.08) * multiplier },
      { name: 'Ponto 2', spend: (clientMetrics.spend * 0.3) * multiplier, revenue: (clientMetrics.revenue * 0.25) * multiplier },
      { name: 'Ponto 3', spend: (clientMetrics.spend * 0.6) * multiplier, revenue: (clientMetrics.revenue * 0.55) * multiplier },
      { name: 'Ponto 4', spend: (clientMetrics.spend * 1.0) * multiplier, revenue: (clientMetrics.revenue * 1.0) * multiplier },
    ];
  }, [clientMetrics, datePreset]);

  const handleSyncData = async (presetOverride?: DatePreset) => {
    setIsSyncing(true);
    setSyncError(null);

    const targetPreset = presetOverride || datePreset;

    try {
      // Se tiver credenciais, faz a chamada real
      if (selectedClient.adAccountId && selectedClient.accessToken) {
        const updatedClient = await syncMetaAdsData(selectedClient, targetPreset);
        setClients(prevClients => 
          prevClients.map(c => c.id === updatedClient.id ? updatedClient : c)
        );
      } else {
        // Simulação para dados mockados
        await new Promise(resolve => setTimeout(resolve, 1200));

        // Se for "máximo", vamos "inflar" os dados mockados para demonstrar a mudança
        if (targetPreset === 'maximum') {
          setClients(prevClients => prevClients.map(c => {
            if (c.id !== selectedClientId) return c;
            return {
              ...c,
              lastSync: `Máximo (${new Date().toLocaleTimeString()})`,
              campaigns: c.campaigns.map(camp => ({
                ...camp,
                metrics: {
                  ...camp.metrics,
                  spend: camp.metrics.spend * 2.5,
                  conversions: Math.floor(camp.metrics.conversions * 2.2),
                  conversionValue: camp.metrics.conversionValue * 2.8,
                  clicks: Math.floor(camp.metrics.clicks * 2.1),
                  impressions: Math.floor(camp.metrics.impressions * 2.4)
                }
              }))
            };
          }));
        } else {
          // Reset para valores originais se não for máximo (simulando filtro de mês)
          // Na vida real, o MOCK_CLIENTS seria apenas o estado inicial e o reset viria de um cache
          // Aqui apenas forçamos uma atualização visual
          setClients([...MOCK_CLIENTS]);
        }
      }
    } catch (error: any) {
      setSyncError(error.message);
      setTimeout(() => setSyncError(null), 5000);
    } finally {
      setIsSyncing(false);
    }
  };

  // Dispara a sincronização SEMPRE que o período ou o cliente mudar
  useEffect(() => {
    handleSyncData(datePreset);
  }, [datePreset, selectedClientId]);

  const handleSaveAccount = (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accessToken, accountInfo } = data;
    const officialId = accountInfo.id;

    setClients(prevClients => {
      const existingClientIndex = prevClients.findIndex(c => 
        (c.adAccountId && c.adAccountId === officialId) ||
        (editingClient && c.id === editingClient.id)
      );

      if (existingClientIndex >= 0) {
        const updatedClients = [...prevClients];
        updatedClients[existingClientIndex] = {
          ...updatedClients[existingClientIndex],
          name: accountInfo.name,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Configuração Atualizada'
        };
        setSelectedClientId(updatedClients[existingClientIndex].id);
        return updatedClients;
      } else {
        const newClient: Client = {
          id: `c_${Date.now()}`,
          name: accountInfo.name,
          industry: 'Geral',
          avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
          adAccountId: officialId,
          accessToken: accessToken,
          lastSync: 'Aguardando Sinc.',
          campaigns: []
        };
        setSelectedClientId(newClient.id);
        return [...prevClients, newClient];
      }
    });
  };

  const handleDeleteClient = (id: string) => {
    setClients(prevClients => {
      const filtered = prevClients.filter(c => c.id !== id);
      if (selectedClientId === id && filtered.length > 0) {
        setSelectedClientId(filtered[0].id);
      }
      return filtered;
    });
  };

  const openSettingsForNew = () => {
    setEditingClient(null);
    setIsSettingsOpen(true);
  };

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={openSettingsForNew}
        onDeleteClient={handleDeleteClient}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
      />

      <main className="flex-1 w-full lg:ml-64 transition-all duration-300 overflow-x-hidden relative">
        {/* Overlay de Sincronização Geral */}
        {isSyncing && (
          <div className="absolute inset-0 bg-white/40 backdrop-blur-[2px] z-20 flex items-center justify-center">
            <div className="bg-white p-6 rounded-3xl shadow-2xl border border-slate-100 flex flex-col items-center gap-4 animate-fade-in-up">
               <div className="relative">
                 <RefreshCw className="w-10 h-10 text-indigo-600 animate-spin" />
                 <div className="absolute inset-0 flex items-center justify-center">
                    <div className="w-2 h-2 bg-indigo-600 rounded-full animate-ping"></div>
                 </div>
               </div>
               <p className="text-[10px] font-black text-slate-900 uppercase tracking-widest">Sincronizando período: {datePreset.replace('_', ' ')}</p>
            </div>
          </div>
        )}

        {/* Mobile Navbar */}
        <div className="lg:hidden flex items-center justify-between p-4 bg-white border-b border-slate-200 sticky top-0 z-30">
          <button onClick={() => setIsSidebarOpen(true)} className="p-2 hover:bg-slate-100 rounded-lg">
             <Menu className="w-6 h-6 text-slate-600" />
          </button>
          <div className="flex flex-col items-center">
             <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Cliente Selecionado</span>
             <h4 className="text-xs font-black text-indigo-600">{selectedClient.name}</h4>
          </div>
          <button onClick={() => handleSyncData()} className="p-2 text-indigo-600">
             <RefreshCw className={`w-5 h-5 ${isSyncing ? 'animate-spin' : ''}`} />
          </button>
        </div>

        <div className="p-4 md:p-8 space-y-8">
          <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
            <div>
              <div className="flex items-center gap-3">
                 <h1 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">Painel de Tráfego</h1>
                 {syncError && (
                   <span className="hidden md:flex items-center text-[10px] font-black text-rose-600 bg-rose-50 px-3 py-1 rounded-full border border-rose-100 uppercase">
                     <AlertTriangle className="w-3 h-3 mr-1" /> Erro na API
                   </span>
                 )}
              </div>
              <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                Analisando <span className="font-bold text-indigo-600">{selectedClient.name}</span> • <span className="text-slate-400">Visto em: {selectedClient.lastSync}</span>
              </p>
            </div>

            <div className="flex flex-wrap gap-2 w-full md:w-auto">
              <button 
                onClick={() => handleSyncData()}
                disabled={isSyncing}
                className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-4 py-2.5 rounded-xl text-xs font-black uppercase shadow-lg shadow-indigo-100 active:scale-95 transition-all disabled:bg-slate-400"
              >
                <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                {isSyncing ? 'Atualizando' : 'Sincronizar'}
              </button>
              <DateRangePicker 
                selected={datePreset} 
                onSelect={setDatePreset} 
              />
            </div>
          </header>

          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
            <StatCard label="Investimento" value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} trend={datePreset === 'maximum' ? 145 : 12} icon={<DollarSign />} />
            <StatCard label="ROAS" value={`${roas}x`} trend={datePreset === 'maximum' ? 15 : -2} icon={<BarChart2 />} />
            <StatCard label="Conversões" value={clientMetrics.conversions.toString()} trend={datePreset === 'maximum' ? 210 : 8} icon={<ShoppingBag />} />
            <StatCard label="CTR Médio" value={`${ctr}%`} neutral icon={<MousePointer />} />
          </div>

          <div className="bg-white p-4 md:p-8 rounded-[32px] border border-slate-200 shadow-sm overflow-hidden">
            <div className="flex justify-between items-center mb-8">
              <h3 className="font-black text-slate-900 uppercase tracking-widest text-xs flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-indigo-600" /> Curva de Performance ({datePreset.replace('_', ' ')})
              </h3>
            </div>
            <div className="h-[250px] md:h-[350px] w-full">
              <ResponsiveContainer width="100%" height="100%">
                <AreaChart data={chartData}>
                  <defs>
                    <linearGradient id="colorRevenue" x1="0" y1="0" x2="0" y2="1">
                      <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.1}/>
                      <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                    </linearGradient>
                  </defs>
                  <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                  <YAxis hide />
                  <CartesianGrid vertical={false} stroke="#f8fafc" />
                  <Tooltip contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                  <Area type="monotone" dataKey="revenue" stroke="#4f46e5" fillOpacity={1} fill="url(#colorRevenue)" strokeWidth={4} animationDuration={1500} />
                </AreaChart>
              </ResponsiveContainer>
            </div>
          </div>

          <div className="space-y-6">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
              <h2 className="text-xl font-black text-slate-900 tracking-tight">Campanhas no Período</h2>
              <div className="relative w-full md:w-72">
                 <input 
                  type="text" 
                  placeholder="Filtrar campanha..." 
                  className="w-full pl-10 pr-4 py-3 bg-white border border-slate-200 rounded-xl text-xs font-bold focus:outline-none focus:ring-2 focus:ring-indigo-500 shadow-sm"
                 />
                 <Search className="w-4 h-4 text-slate-400 absolute left-3.5 top-1/2 -translate-y-1/2" />
              </div>
            </div>

            {selectedClient.campaigns.length === 0 ? (
              <div className="bg-white rounded-3xl p-12 text-center border-2 border-slate-100 border-dashed">
                <p className="text-slate-400 font-bold uppercase text-[10px] tracking-widest">Sem campanhas para este período.</p>
              </div>
            ) : (
              <div className="grid grid-cols-1 xl:grid-cols-2 gap-4 md:gap-6">
                {selectedClient.campaigns.map((campaign) => (
                  <div 
                    key={campaign.id} 
                    onClick={() => setSelectedCampaign(campaign)}
                    className="bg-white rounded-[28px] border border-slate-200 shadow-sm hover:shadow-xl hover:border-indigo-300 transition-all cursor-pointer group flex flex-col sm:flex-row overflow-hidden animate-fade-in"
                  >
                    <div className="w-full sm:w-44 h-44 sm:h-auto bg-slate-100 flex-shrink-0 relative overflow-hidden">
                      <img src={campaign.creative.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-700" />
                      <span className="absolute top-3 left-3 bg-slate-900 text-white text-[8px] font-black px-2 py-1 rounded-lg uppercase tracking-widest">{campaign.platform}</span>
                    </div>

                    <div className="p-6 flex-1 flex flex-col justify-between bg-white">
                      <div>
                        <div className="flex justify-between items-start mb-2 gap-2">
                          <h3 className="font-black text-slate-900 text-sm group-hover:text-indigo-600 transition-colors line-clamp-1">{campaign.name}</h3>
                          <span className={`px-2 py-1 rounded-lg text-[8px] font-black uppercase flex-shrink-0 ${campaign.status === 'active' ? 'bg-emerald-100 text-emerald-600' : 'bg-slate-100 text-slate-500'}`}>
                            {campaign.status}
                          </span>
                        </div>
                        <p className="text-[10px] text-slate-400 font-bold uppercase flex items-center gap-1 mb-4">
                          <Target className="w-3 h-3 text-indigo-500" /> {campaign.objective}
                        </p>

                        <div className="grid grid-cols-3 gap-2 pt-4 border-t border-slate-50">
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">Gasto</p>
                            <p className="font-black text-slate-900 text-xs">R$ {campaign.metrics.spend.toLocaleString('pt-BR')}</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">ROAS</p>
                            <p className="font-black text-indigo-600 text-xs">{(campaign.metrics.conversionValue / (campaign.metrics.spend || 1)).toFixed(1)}x</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black">CTR</p>
                            <p className="font-black text-slate-900 text-xs">{((campaign.metrics.clicks / (campaign.metrics.impressions || 1)) * 100).toFixed(1)}%</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </div>
        </div>
      </main>

      {selectedCampaign && (
        <CampaignDetails 
          campaign={selectedCampaign} 
          onClose={() => setSelectedCampaign(null)} 
        />
      )}

      <SettingsModal
        initialClient={editingClient}
        isOpen={isSettingsOpen}
        onClose={() => setIsSettingsOpen(false)}
        onSave={handleSaveAccount}
      />
    </div>
  );
}

export default App;

