                <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                  ID: <span className="text-slate-900 font-bold">{selectedClient.adAccountId}</span> • Última Sync: <span className="text-indigo-600 font-bold">{selectedClient.lastSync}</span>
                </p>
