              <div className="bg-indigo-100 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6">
                <PlusCircle className="w-8 h-8 text-indigo-600" />
              </div>
              <h2 className="text-xl font-black text-slate-900 mb-2">Painel de Gestão</h2>
              <p className="text-slate-500 text-sm font-medium mb-8">Conecte uma conta de anúncios do Meta para centralizar seus resultados.</p>
