      }, (error) => {
        console.error("Erro no Firestore Snapshot:", error);
        setSyncError("Conexão instável com o banco de dados.");
      });
      return () => unsubscribe();
    } catch (err) {
      console.error("Erro ao iniciar snapshot:", err);
      setSyncError("Erro crítico de inicialização.");
    }
