import { Client, Campaign, AdSet, Ad, Metrics, DemographicData, VideoMetrics } from "../types.ts";

export interface MetaAccountInfo {
  id: string;
  name: string;
  currency: string;
}

const getActionValue = (actions: any[], actionType: string): number => {
  if (!actions || !Array.isArray(actions)) return 0;
  const action = actions.find((a: any) => a.action_type === actionType);
  return action ? parseFloat(action.value || action.count || 0) : 0;
};

const mapDatePreset = (preset: string): string => {
  const mapping: Record<string, string> = {
    'maximum': 'maximum',
    'today': 'today',
    'yesterday': 'yesterday',
    'today_and_yesterday': 'last_3d',
    'last_7d': 'last_7d',
    'last_14d': 'last_14d',
    'last_28d': 'last_28d',
    'last_30d': 'last_30d',
    'this_week': 'this_week_mon_today',
    'last_week': 'last_week_mon_sun',
    'this_month': 'this_month',
    'last_month': 'last_month'
  };
  return mapping[preset] || 'this_month';
};

const mapInsightsToMetrics = (insightsData: any): Metrics => {
  const insights = insightsData?.data?.[0] || {};
  const actions = insights.actions || [];
  const messages = getActionValue(actions, 'onsite_conversion.messaging_first_reply');
  const spend = parseFloat(insights.spend || 0);

  const videoPlays = getActionValue(actions, 'video_play');
  let video: VideoMetrics | undefined = undefined;

  if (videoPlays > 0) {
    video = {
      plays: videoPlays,
      avgTime: parseFloat(insights.video_avg_time_watched_actions?.[0]?.value || 0),
      retention25: getActionValue(actions, 'video_p25_watched_actions'),
      retention50: getActionValue(actions, 'video_p50_watched_actions'),
      retention75: getActionValue(actions, 'video_p75_watched_actions'),
      retention100: getActionValue(actions, 'video_p100_watched_actions'),
    };
  }

  const metrics: Metrics = {
    spend,
    impressions: parseInt(insights.impressions || 0),
    reach: parseInt(insights.reach || 0),
    frequency: parseFloat(insights.frequency || 0),
    cpm: parseFloat(insights.cpm || 0),
    clicks: parseInt(insights.clicks || 0),
    conversions: getActionValue(actions, 'purchase'),
    conversionValue: getActionValue(insights.action_values, 'purchase'),
  };

  if (messages > 0) {
    metrics.messages = messages;
    metrics.costPerMessage = spend / messages;
  }

  if (video) {
    metrics.video = video;
  }

  return metrics;
};

export const validateMetaConnection = async (adAccountId: string, accessToken: string): Promise<MetaAccountInfo> => {
  const cleanActId = adAccountId.replace('act_', '').trim();
  const url = `https://graph.facebook.com/v19.0/act_${cleanActId}?fields=name,currency&access_token=${accessToken}`;
  const response = await fetch(url);
  const json = await response.json();
  if (json.error) throw new Error(json.error.message);
  return { id: json.id, name: json.name, currency: json.currency };
};

export const syncMetaAdsData = async (
  client: Client, 
  datePreset: string = 'this_month',
  customRange?: { since: string; until: string }
): Promise<Client> => {
  if (!client.adAccountId || !client.accessToken) throw new Error("Credenciais ausentes.");

  const accountId = client.adAccountId.startsWith('act_') ? client.adAccountId : `act_${client.adAccountId}`;
  const token = client.accessToken;
  const insightsFields = `spend,impressions,reach,frequency,cpm,clicks,actions,action_values,video_avg_time_watched_actions`;

  // Define o seletor de data (Preset ou Range Personalizado)
  let dateQuery = '';
  if (datePreset === 'custom' && customRange) {
    const range = JSON.stringify({ since: customRange.since, until: customRange.until });
    dateQuery = `time_range=${range}`;
  } else {
    dateQuery = `date_preset=${mapDatePreset(datePreset)}`;
  }

  const insightsParams = `.${dateQuery.replace('=', '(').replace(/$/, ')')}`;

  try {
    const url = `https://graph.facebook.com/v19.0/${accountId}/campaigns?fields=id,name,status,objective,daily_budget,lifetime_budget,start_time,stop_time,insights${insightsParams}{${insightsFields}},adsets{id,name,status,daily_budget,lifetime_budget,targeting,insights${insightsParams}{${insightsFields}},ads{id,name,status,creative{id,title,image_url,thumbnail_url},insights${insightsParams}{${insightsFields}}}}&${dateQuery}&access_token=${token}`;

    const response = await fetch(url);
    const json = await response.json();
    if (json.error) throw new Error(json.error.message);

    const campaigns: Campaign[] = await Promise.all(json.data.map(async (fbCamp: any) => {
      const demoUrl = `https://graph.facebook.com/v19.0/${fbCamp.id}/insights?breakdowns=age,gender&fields=spend,actions&${dateQuery}&access_token=${token}`;
      const demoRes = await fetch(demoUrl);
      const demoJson = await demoRes.json();
      const demographics: DemographicData[] = (demoJson.data || []).map((d: any) => ({
        age: d.age,
        gender: d.gender,
        spend: parseFloat(d.spend || 0),
        results: getActionValue(d.actions, fbCamp.objective === 'MESSAGES' ? 'onsite_conversion.messaging_first_reply' : 'purchase')
      }));

      const campMetrics = { ...mapInsightsToMetrics(fbCamp.insights), demographics };
      const adSets: AdSet[] = (fbCamp.adsets?.data || []).map((fbAdSet: any) => {
        const ads: Ad[] = (fbAdSet.ads?.data || []).map((fbAd: any) => ({
          id: fbAd.id,
          name: fbAd.name,
          status: fbAd.status === 'ACTIVE' ? 'active' : 'paused',
          creative: {
            id: fbAd.creative?.id || '0',
            type: 'image',
            url: fbAd.creative?.image_url || fbAd.creative?.thumbnail_url || 'https://via.placeholder.com/150',
            headline: fbAd.creative?.title || fbAd.name
          },
          metrics: mapInsightsToMetrics(fbAd.insights)
        }));
        return {
          id: fbAdSet.id,
          name: fbAdSet.name,
          status: fbAdSet.status === 'ACTIVE' ? 'active' : 'paused',
          budget: parseFloat(fbAdSet.daily_budget || fbAdSet.lifetime_budget || 0) / 100,
          budgetType: fbAdSet.daily_budget ? 'DAILY' : 'LIFETIME',
          audience: JSON.stringify(fbAdSet.targeting || {}),
          metrics: mapInsightsToMetrics(fbAdSet.insights),
          ads
        };
      });
      return {
        id: fbCamp.id,
        name: fbCamp.name,
        status: fbCamp.status === 'ACTIVE' ? 'active' : 'paused',
        platform: 'facebook',
        objective: fbCamp.objective,
        metrics: campMetrics,
        budget: parseFloat(fbCamp.daily_budget || fbCamp.lifetime_budget || 0) / 100,
        budgetType: fbCamp.daily_budget ? 'DAILY' : 'LIFETIME',
        startTime: fbCamp.start_time || null,
        endTime: fbCamp.stop_time || null,
        adSets,
        creative: adSets[0]?.ads[0]?.creative || { id: '0', type: 'image', url: '', headline: fbCamp.name },
        audience: adSets[0]?.name || 'Público Geral'
      };
    }));
    return { ...client, lastSync: new Date().toLocaleTimeString(), campaigns };
  } catch (e: any) {
    throw e;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Calendar, ChevronDown, Check } from 'lucide-react';

export type DatePreset = 
  | 'maximum' | 'today' | 'yesterday' | 'today_and_yesterday' 
  | 'last_7d' | 'last_14d' | 'last_28d' | 'last_30d' 
  | 'this_week' | 'last_week' | 'this_month' | 'last_month' 
  | 'custom';

interface DateRangePickerProps {
  selected: DatePreset;
  onSelect: (preset: DatePreset, customRange?: { since: string; until: string }) => void;
  initialCustomRange?: { since: string; until: string };
}

const PRESETS: { id: DatePreset; label: string }[] = [
  { id: 'maximum', label: 'Máximo' },
  { id: 'today', label: 'Hoje' },
  { id: 'yesterday', label: 'Ontem' },
  { id: 'today_and_yesterday', label: 'Hoje e ontem' },
  { id: 'last_7d', label: 'Últimos 7 dias' },
  { id: 'last_14d', label: 'Últimos 14 dias' },
  { id: 'last_28d', label: 'Últimos 28 dias' },
  { id: 'last_30d', label: 'Últimos 30 dias' },
  { id: 'this_week', label: 'Esta semana' },
  { id: 'last_week', label: 'Semana passada' },
  { id: 'this_month', label: 'Este mês' },
  { id: 'last_month', label: 'Mês passado' },
  { id: 'custom', label: 'Personalizado' },
];

export const DateRangePicker: React.FC<DateRangePickerProps> = ({ selected, onSelect, initialCustomRange }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [since, setSince] = useState(initialCustomRange?.since || '');
  const [until, setUntil] = useState(initialCustomRange?.until || '');
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const handleClickOutside = (event: MouseEvent) => {
      if (containerRef.current && !containerRef.current.contains(event.target as Node)) {
        setIsOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleApplyCustom = () => {
    if (since && until) {
      onSelect('custom', { since, until });
      setIsOpen(false);
    }
  };

  const selectedLabel = selected === 'custom' && initialCustomRange 
    ? `${initialCustomRange.since} a ${initialCustomRange.until}`
    : PRESETS.find(p => p.id === selected)?.label || 'Período';

  return (
    <div className="relative" ref={containerRef}>
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className="flex items-center gap-2 bg-white border border-slate-200 text-slate-600 px-4 py-2.5 rounded-xl text-xs font-black uppercase shadow-sm hover:border-indigo-300 transition-all whitespace-nowrap"
      >
        <Calendar className="w-4 h-4 text-indigo-600" />
        {selectedLabel}
        <ChevronDown className={`w-3 h-3 transition-transform ${isOpen ? 'rotate-180' : ''}`} />
      </button>

      {isOpen && (
        <div className="absolute right-0 mt-2 w-72 bg-white border border-slate-200 rounded-2xl shadow-2xl z-[100] py-4 animate-fade-in-up flex flex-col">
          <div className="px-6 pb-2 mb-2 border-b border-slate-100 flex items-center justify-between">
            <h4 className="text-[11px] font-black text-slate-400 uppercase tracking-widest">Escolha o Período</h4>
          </div>

          <div className="max-h-[300px] overflow-y-auto custom-scrollbar">
            {PRESETS.filter(p => p.id !== 'custom').map((preset) => (
              <button 
                key={preset.id}
                onClick={() => {
                  onSelect(preset.id);
                  setIsOpen(false);
                }}
                className={`w-full text-left px-6 py-2.5 hover:bg-slate-50 transition-colors flex items-center justify-between group ${selected === preset.id ? 'bg-indigo-50/50' : ''}`}
              >
                <span className={`text-sm font-semibold ${selected === preset.id ? 'text-indigo-600' : 'text-slate-500 group-hover:text-slate-700'}`}>
                  {preset.label}
                </span>
                {selected === preset.id && <Check className="w-4 h-4 text-indigo-600" />}
              </button>
            ))}
          </div>

          <div className="p-4 bg-slate-50 border-t border-slate-100 mt-2 rounded-b-2xl">
             <h5 className="text-[10px] font-black text-slate-400 uppercase mb-3 flex items-center gap-2">
               <Calendar className="w-3 h-3" /> Personalizado
             </h5>
             <div className="space-y-3">
               <div className="grid grid-cols-2 gap-2">
                 <div>
                   <label className="text-[8px] font-black text-slate-400 uppercase mb-1 block">Início</label>
                   <input 
                     type="date" 
                     value={since}
                     onChange={(e) => setSince(e.target.value)}
                     className="w-full text-[10px] p-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-indigo-500 font-bold"
                   />
                 </div>
                 <div>
                   <label className="text-[8px] font-black text-slate-400 uppercase mb-1 block">Fim</label>
                   <input 
                     type="date" 
                     value={until}
                     onChange={(e) => setUntil(e.target.value)}
                     className="w-full text-[10px] p-2 border border-slate-200 rounded-lg outline-none focus:ring-1 focus:ring-indigo-500 font-bold"
                   />
                 </div>
               </div>
               <button 
                onClick={handleApplyCustom}
                disabled={!since || !until}
                className="w-full bg-slate-900 text-white py-2 rounded-lg text-[10px] font-black uppercase tracking-widest hover:bg-indigo-600 transition-all disabled:opacity-50"
               >
                 Aplicar Período
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Sidebar } from './components/Sidebar.tsx';
import { StatCard } from './components/StatCard.tsx';
import { CampaignDetails } from './components/CampaignDetails.tsx';
import { SettingsModal } from './components/SettingsModal.tsx';
import { DateRangePicker, DatePreset } from './components/DateRangePicker.tsx';
import { Login } from './components/Login.tsx';
import { Client, Campaign } from './types.ts';
import { Menu, Search, BarChart2, DollarSign, MousePointer, ShoppingBag, RefreshCw, TrendingUp, Loader2, PlusCircle, Database, AlertCircle, WifiOff, Clock, Target, Users } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { syncMetaAdsData, MetaAccountInfo } from './services/metaService.ts';
import { db } from './firebase.ts';
import { collection, onSnapshot, setDoc, doc, deleteDoc, query } from 'firebase/firestore';

const sanitizeData = (obj: any): any => {
  if (Array.isArray(obj)) {
    return obj.map(sanitizeData);
  } else if (obj !== null && typeof obj === 'object') {
    return Object.fromEntries(
      Object.entries(obj)
        .filter(([_, v]) => v !== undefined)
        .map(([k, v]) => [k, sanitizeData(v)])
    );
  }
  return obj;
};

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(false);
  const [userEmail, setUserEmail] = useState<string | null>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true);

  const [clients, setClients] = useState<Client[]>([]);
  const clientsRef = useRef<Client[]>([]);
  const [selectedClientId, setSelectedClientId] = useState<string>('');
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);

  const [datePreset, setDatePreset] = useState<DatePreset>('this_month');
  const [customRange, setCustomRange] = useState<{ since: string; until: string } | undefined>(undefined);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const initialLoadDone = useRef(false);
  const isFirebaseAvailable = !!db;

  useEffect(() => {
    clientsRef.current = clients;
  }, [clients]);

  useEffect(() => {
    try {
      const savedAuth = localStorage.getItem('ads_manager_auth');
      if (savedAuth) {
        const authData = JSON.parse(savedAuth);
        setIsAuthenticated(true);
        setUserEmail(authData.email);
      }
    } catch (e) {
      console.error("Erro ao ler auth local:", e);
    } finally {
      setIsAuthChecking(false);
    }
  }, []);

  useEffect(() => {
    if (!isAuthenticated || !isFirebaseAvailable) return;

    try {
      const q = query(collection(db, "clients"));
      const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const clientsData: Client[] = [];
        querySnapshot.forEach((doc) => {
          clientsData.push(doc.data() as Client);
        });

        setClients(clientsData);

        setSelectedClientId(currentId => {
          if (currentId && clientsData.some(c => c.id === currentId)) return currentId;
          return clientsData.length > 0 ? clientsData[0].id : '';
        });
      }, (error) => {
        console.error("Erro no Firestore Snapshot:", error);
        setSyncError("Erro de conexão com o banco de dados.");
      });
      return () => unsubscribe();
    } catch (err) {
      console.error("Erro ao iniciar snapshot:", err);
      setSyncError("Erro crítico de inicialização.");
    }
  }, [isAuthenticated, isFirebaseAvailable]);

  const handleSyncData = useCallback(async (clientId: string, preset: DatePreset, range?: { since: string; until: string }) => {
    const clientToSync = clientsRef.current.find(c => c.id === clientId);
    if (!isAuthenticated || !clientToSync || isSyncing) return;

    setIsSyncing(true);
    setSyncError(null);

    try {
      if (clientToSync.adAccountId && clientToSync.accessToken) {
        const updatedClientData = await syncMetaAdsData(clientToSync, preset, range);
        if (isFirebaseAvailable) {
          const sanitized = sanitizeData(updatedClientData);
          await setDoc(doc(db, "clients", sanitized.id), sanitized, { merge: true });
        }
      }
    } catch (error: any) {
      console.error("Erro na sincronização:", error);
      setSyncError(`Falha na sincronização (${clientToSync.name}): ${error.message}`);
    } finally {
      setIsSyncing(false);
    }
  }, [isAuthenticated, isSyncing, isFirebaseAvailable]);

  useEffect(() => {
    if (isAuthenticated && selectedClientId) {
      if (initialLoadDone.current) {
        handleSyncData(selectedClientId, datePreset, customRange);
      } else {
        initialLoadDone.current = true;
      }
    }
  }, [datePreset, selectedClientId, isAuthenticated, customRange]);

  const handleDateSelect = (preset: DatePreset, range?: { since: string; until: string }) => {
    setDatePreset(preset);
    setCustomRange(range);
  };

  const handleLogin = (email: string) => {
    setIsAuthenticated(true);
    setUserEmail(email);
    localStorage.setItem('ads_manager_auth', JSON.stringify({ email, timestamp: Date.now() }));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja realmente sair?')) {
      setIsAuthenticated(false);
      setUserEmail(null);
      localStorage.removeItem('ads_manager_auth');
    }
  };

  const selectedClient = useMemo(() => {
    return clients.find(c => c.id === selectedClientId) || null;
  }, [clients, selectedClientId]);

  const clientMetrics = useMemo(() => {
    if (!selectedClient || !selectedClient.campaigns) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend || 0;
      acc.impressions += curr.metrics.impressions || 0;
      acc.clicks += curr.metrics.clicks || 0;
      acc.conversions += curr.metrics.conversions || 0;
      acc.revenue += curr.metrics.conversionValue || 0;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';

  const chartData = useMemo(() => {
    return [
      { name: 'Jan', spend: (clientMetrics.spend * 0.2), revenue: (clientMetrics.revenue * 0.15) },
      { name: 'Fev', spend: (clientMetrics.spend * 0.5), revenue: (clientMetrics.revenue * 0.45) },
      { name: 'Mar', spend: (clientMetrics.spend * 1.0), revenue: (clientMetrics.revenue * 1.0) },
    ];
  }, [clientMetrics]);

  const handleSaveAccount = async (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accountInfo, accessToken } = data;
    const clientId = `c_${accountInfo.id}`;

    const newClient: Client = {
      id: clientId,
      name: accountInfo.name,
      industry: 'Geral',
      avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
      adAccountId: accountInfo.id,
      accessToken: accessToken,
      lastSync: 'Conectado agora',
      campaigns: []
    };

    try {
      if (isFirebaseAvailable) {
        const sanitized = sanitizeData(newClient);
        await setDoc(doc(db, "clients", sanitized.id), sanitized, { merge: true });
        setSelectedClientId(clientId);
        setIsSettingsOpen(false);
        setTimeout(() => handleSyncData(clientId, datePreset, customRange), 500);
      }
    } catch (e: any) {
      alert("Erro ao salvar no banco de dados.");
    }
  };

  const handleDeleteClient = async (id: string) => {
    if (!window.confirm('Excluir este cliente e todos os dados salvos?')) return;
    try {
      if (isFirebaseAvailable) await deleteDoc(doc(db, "clients", id));
      if (selectedClientId === id) setSelectedClientId('');
    } catch (e) {
      console.error("Erro ao deletar:", e);
    }
  };

  if (isAuthChecking) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
      </div>
    );
  }

  if (!isAuthenticated) return <Login onLogin={handleLogin} />;

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={() => setIsSettingsOpen(true)}
        onDeleteClient={handleDeleteClient}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        onLogout={handleLogout}
      />

      <main className="flex-1 w-full lg:ml-64 transition-all duration-300 overflow-x-hidden relative">
        {syncError && (
          <div className="bg-rose-50 border-b border-rose-200 px-8 py-3 flex items-center gap-3 text-rose-700 text-xs font-bold animate-fade-in">
            <AlertCircle className="w-4 h-4" />
            {syncError}
            <button onClick={() => setSyncError(null)} className="ml-auto text-rose-400 hover:text-rose-600 font-black">X</button>
          </div>
        )}

        {!selectedClient && clients.length === 0 && (
          <div className="absolute inset-0 flex items-center justify-center bg-slate-50 z-10 p-8">
            <div className="text-center max-w-sm">
              <div className="bg-indigo-100 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6">
                <PlusCircle className="w-8 h-8 text-indigo-600" />
              </div>
              <h2 className="text-xl font-black text-slate-900 mb-2">Início do Dashboard</h2>
              <p className="text-slate-500 text-sm font-medium mb-8">Conecte sua primeira conta do Meta Ads para centralizar os dados.</p>
              <button onClick={() => setIsSettingsOpen(true)} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-black uppercase text-xs tracking-widest shadow-xl">
                Conectar Conta
              </button>
            </div>
          </div>
        )}

        {selectedClient && (
          <div className="p-4 md:p-8 space-y-8 animate-fade-in pb-20">
            <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <div className="flex items-center gap-4 w-full md:w-auto">
                <button 
                  onClick={() => setIsSidebarOpen(true)}
                  className="lg:hidden p-2 bg-white border border-slate-200 rounded-xl text-slate-600"
                >
                  <Menu className="w-6 h-6" />
                </button>
                <div>
                  <div className="flex items-center gap-3">
                     <h1 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">{selectedClient.name}</h1>
                     <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-1 rounded border border-emerald-100 uppercase flex items-center gap-1">
                       <Database className="w-3 h-3" /> Online
                     </span>
                  </div>
                  <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                    ID: <span className="text-slate-900 font-bold">{selectedClient.adAccountId}</span> • Sync: <span className="text-indigo-600 font-bold">{selectedClient.lastSync}</span>
                  </p>
                </div>
              </div>

              <div className="flex flex-wrap gap-3 w-full md:w-auto">
                <button 
                  onClick={() => handleSyncData(selectedClientId, datePreset, customRange)}
                  disabled={isSyncing}
                  className={`flex-1 md:flex-none flex items-center justify-center gap-3 px-6 py-3 rounded-xl text-xs font-black uppercase transition-all shadow-lg active:scale-95 ${
                    isSyncing 
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200'
                  }`}
                >
                  <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                  {isSyncing ? 'Sincronizando...' : 'Sincronizar Agora'}
                </button>
                <DateRangePicker 
                  selected={datePreset} 
                  onSelect={handleDateSelect} 
                  initialCustomRange={customRange}
                />
              </div>
            </header>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
              <StatCard label="Total Gasto" value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} trend={12} icon={<DollarSign />} />
              <StatCard label="ROAS Médio" value={`${roas}x`} trend={8} icon={<BarChart2 />} />
              <StatCard label="Conversões" value={clientMetrics.conversions.toString()} trend={15} icon={<ShoppingBag />} />
              <StatCard label="Cliques Únicos" value={clientMetrics.clicks.toLocaleString('pt-BR')} icon={<MousePointer />} />
            </div>

            <div className="bg-white p-6 md:p-8 rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
              <h3 className="font-black text-slate-900 uppercase tracking-widest text-[10px] mb-8 flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-indigo-600" /> Histórico de Performance
              </h3>
              <div className="h-[300px] w-full min-w-0 relative">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData}>
                    <defs>
                      <linearGradient id="colorSpend" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.15}/>
                        <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid vertical={false} stroke="#f1f5f9" strokeDasharray="3 3" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                    <YAxis hide />
                    <Tooltip contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}} />
                    <Area type="monotone" dataKey="spend" stroke="#4f46e5" fill="url(#colorSpend)" strokeWidth={4} name="Gasto" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-end justify-between">
                <h2 className="text-xl font-black text-slate-900 tracking-tight uppercase text-[12px] tracking-widest">Campanhas Ativas</h2>
                <div className="relative">
                   <input type="text" placeholder="Filtrar..." className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm min-w-[200px]" />
                   <Search className="w-4 h-4 text-slate-400 absolute left-3.5 top-1/2 -translate-y-1/2" />
                </div>
              </div>

              {selectedClient.campaigns.length === 0 ? (
                <div className="bg-white rounded-[32px] p-16 text-center border-2 border-slate-100 border-dashed">
                  <Database className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Aguardando dados da Meta Ads...</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                  {selectedClient.campaigns.map((campaign) => (
                    <div 
                      key={campaign.id} 
                      onClick={() => setSelectedCampaign(campaign)}
                      className="bg-white rounded-[32px] border border-slate-200 shadow-sm hover:shadow-xl hover:border-indigo-300 transition-all cursor-pointer group flex flex-col md:flex-row overflow-hidden"
                    >
