  clientId?: string;
}

const sanitizeData = (obj: any): any => {
  if (Array.isArray(obj)) {
    return obj.map(sanitizeData);
  } else if (obj !== null && typeof obj === 'object') {
    return Object.fromEntries(
      Object.entries(obj)
        .filter(([_, v]) => v !== undefined)
        .map(([k, v]) => [k, sanitizeData(v)])
    );
  }
  return obj;
};

function App() {
  const [session, setSession] = useState<UserSession | null>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true);

  const [clients, setClients] = useState<Client[]>([]);
  const clientsRef = useRef<Client[]>([]);
  const [selectedClientId, setSelectedClientId] = useState<string>('');
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);

  const [datePreset, setDatePreset] = useState<DatePreset>('this_month');
  const [customRange, setCustomRange] = useState<{ since: string; until: string } | undefined>(undefined);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isAccessModalOpen, setIsAccessModalOpen] = useState(false);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const initialLoadDone = useRef(false);
  const isFirebaseAvailable = !!db;

  useEffect(() => {
    clientsRef.current = clients;
  }, [clients]);

  useEffect(() => {
    try {
      const savedAuth = localStorage.getItem('ads_manager_auth_v2');
      if (savedAuth) {
        setSession(JSON.parse(savedAuth));
      }
    } catch (e) {
      console.error("Erro ao ler auth local:", e);
    } finally {
      setIsAuthChecking(false);
    }
  }, []);

  useEffect(() => {
    if (!session || !isFirebaseAvailable) return;

    try {
      const q = query(collection(db, "clients"));
      const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const clientsData: Client[] = [];
        querySnapshot.forEach((doc) => {
          clientsData.push(doc.data() as Client);
        });

        setClients(clientsData);

        // Se for cliente, travar o ID. Se for admin, manter lógica normal.
        if (session.role === 'client' && session.clientId) {
          setSelectedClientId(session.clientId);
        } else {
          setSelectedClientId(currentId => {
            if (currentId && clientsData.some(c => c.id === currentId)) return currentId;
            return clientsData.length > 0 ? clientsData[0].id : '';
          });
        }
      }, (error) => {
        console.error("Erro no Firestore Snapshot:", error);
        setSyncError("Erro de conexão com o banco de dados.");
      });
      return () => unsubscribe();
    } catch (err) {
      console.error("Erro ao iniciar snapshot:", err);
      setSyncError("Erro crítico de inicialização.");
    }
  }, [session, isFirebaseAvailable]);

  const handleSyncData = useCallback(async (clientId: string, preset: DatePreset, range?: { since: string; until: string }) => {
    const clientToSync = clientsRef.current.find(c => c.id === clientId);
    if (!session || !clientToSync || isSyncing) return;

    setIsSyncing(true);
    setSyncError(null);

    try {
      if (clientToSync.adAccountId && clientToSync.accessToken) {
        const updatedClientData = await syncMetaAdsData(clientToSync, preset, range);
        if (isFirebaseAvailable) {
          const sanitized = sanitizeData(updatedClientData);
          await setDoc(doc(db, "clients", sanitized.id), sanitized, { merge: true });
        }
      }
    } catch (error: any) {
      console.error("Erro na sincronização:", error);
      setSyncError(`Falha na sincronização (${clientToSync.name}): ${error.message}`);
    } finally {
      setIsSyncing(false);
    }
  }, [session, isSyncing, isFirebaseAvailable]);

  useEffect(() => {
    if (session && selectedClientId) {
      if (initialLoadDone.current) {
        handleSyncData(selectedClientId, datePreset, customRange);
      } else {
        initialLoadDone.current = true;
      }
    }
  }, [datePreset, selectedClientId, session, customRange]);

  const handleDateSelect = (preset: DatePreset, range?: { since: string; until: string }) => {
    setDatePreset(preset);
    setCustomRange(range);
  };

  const handleLogin = (user: UserSession) => {
    setSession(user);
    localStorage.setItem('ads_manager_auth_v2', JSON.stringify(user));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja realmente sair?')) {
      setSession(null);
      localStorage.removeItem('ads_manager_auth_v2');
    }
  };

  const handleUpdateClientAccess = async (clientId: string, email: string, pass: string) => {
    if (!isFirebaseAvailable) return;
    const clientRef = doc(db, "clients", clientId);
    await setDoc(clientRef, { loginEmail: email, loginPassword: pass }, { merge: true });
  };

  const selectedClient = useMemo(() => {
    return clients.find(c => c.id === selectedClientId) || null;
  }, [clients, selectedClientId]);

  const clientMetrics = useMemo(() => {
    if (!selectedClient || !selectedClient.campaigns) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend || 0;
      acc.impressions += curr.metrics.impressions || 0;
      acc.clicks += curr.metrics.clicks || 0;
      acc.conversions += curr.metrics.conversions || 0;
      acc.revenue += curr.metrics.conversionValue || 0;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';

  const chartData = useMemo(() => {
    return [
      { name: 'Jan', spend: (clientMetrics.spend * 0.2), revenue: (clientMetrics.revenue * 0.15) },
      { name: 'Fev', spend: (clientMetrics.spend * 0.5), revenue: (clientMetrics.revenue * 0.45) },
      { name: 'Mar', spend: (clientMetrics.spend * 1.0), revenue: (clientMetrics.revenue * 1.0) },
    ];
  }, [clientMetrics]);

  const handleSaveAccount = async (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accountInfo, accessToken } = data;
    const clientId = `c_${accountInfo.id}`;

    const newClient: Client = {
      id: clientId,
      name: accountInfo.name,
      industry: 'Geral',
      avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
      adAccountId: accountInfo.id,
      accessToken: accessToken,
      lastSync: 'Conectado agora',
      campaigns: []
    };

    try {
      if (isFirebaseAvailable) {
        const sanitized = sanitizeData(newClient);
        await setDoc(doc(db, "clients", sanitized.id), sanitized, { merge: true });
        setSelectedClientId(clientId);
        setIsSettingsOpen(false);
        setTimeout(() => handleSyncData(clientId, datePreset, customRange), 500);
      }
    } catch (e: any) {
      alert("Erro ao salvar no banco de dados.");
    }
  };

  const handleDeleteClient = async (id: string) => {
    if (!window.confirm('Excluir este cliente e todos os dados salvos?')) return;
    try {
      if (isFirebaseAvailable) await deleteDoc(doc(db, "clients", id));
      if (selectedClientId === id) setSelectedClientId('');
    } catch (e) {
      console.error("Erro ao deletar:", e);
    }
  };

  if (isAuthChecking) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
      </div>
    );
  }

  if (!session) return <Login onLogin={handleLogin} />;

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={() => setIsSettingsOpen(true)}
        onOpenAccessManagement={() => setIsAccessModalOpen(true)}
        onDeleteClient={handleDeleteClient}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        onLogout={handleLogout}
        isAdmin={session.role === 'admin'}
      />

      <main className="flex-1 w-full lg:ml-64 transition-all duration-300 overflow-x-hidden relative">
        {syncError && (
          <div className="bg-rose-50 border-b border-rose-200 px-8 py-3 flex items-center gap-3 text-rose-700 text-xs font-bold animate-fade-in">
            <AlertCircle className="w-4 h-4" />
            {syncError}
            <button onClick={() => setSyncError(null)} className="ml-auto text-rose-400 hover:text-rose-600 font-black">X</button>
          </div>
        )}

        {!selectedClient && clients.length === 0 && (
          <div className="absolute inset-0 flex items-center justify-center bg-slate-50 z-10 p-8">
            <div className="text-center max-w-sm">
              <div className="bg-indigo-100 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6">
                <PlusCircle className="w-8 h-8 text-indigo-600" />
              </div>
              <h2 className="text-xl font-black text-slate-900 mb-2">Início do Dashboard</h2>
              <p className="text-slate-500 text-sm font-medium mb-8">Conecte sua primeira conta do Meta Ads para centralizar os dados.</p>
              {session.role === 'admin' && (
                <button onClick={() => setIsSettingsOpen(true)} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-black uppercase text-xs tracking-widest shadow-xl">
                  Conectar Conta
                </button>
              )}
            </div>
          </div>
        )}

        {selectedClient && (
          <div className="p-4 md:p-8 space-y-8 animate-fade-in pb-20">
            <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <div className="flex items-center gap-4 w-full md:w-auto">
                <button 
                  onClick={() => setIsSidebarOpen(true)}
                  className="lg:hidden p-2 bg-white border border-slate-200 rounded-xl text-slate-600"
                >
                  <Menu className="w-6 h-6" />
                </button>
                <div>
                  <div className="flex items-center gap-3">
                     <h1 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">{selectedClient.name}</h1>
                     <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-1 rounded border border-emerald-100 uppercase flex items-center gap-1">
                       <Database className="w-3 h-3" /> Online
                     </span>
                  </div>
                  <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                    ID: <span className="text-slate-900 font-bold">{selectedClient.adAccountId}</span> • Sync: <span className="text-indigo-600 font-bold">{selectedClient.lastSync}</span>
                  </p>
                </div>
              </div>

              <div className="flex flex-wrap gap-3 w-full md:w-auto">
                <button 
                  onClick={() => handleSyncData(selectedClientId, datePreset, customRange)}
                  disabled={isSyncing}
                  className={`flex-1 md:flex-none flex items-center justify-center gap-3 px-6 py-3 rounded-xl text-xs font-black uppercase transition-all shadow-lg active:scale-95 ${
                    isSyncing 
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200'
                  }`}
                >
                  <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                  {isSyncing ? 'Sincronizando...' : 'Sincronizar Agora'}
                </button>
                <DateRangePicker 
                  selected={datePreset} 
                  onSelect={handleDateSelect} 
                  initialCustomRange={customRange}
                />
              </div>
            </header>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
              <StatCard label="Total Gasto" value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} trend={12} icon={<DollarSign />} />
              <StatCard label="ROAS Médio" value={`${roas}x`} trend={8} icon={<BarChart2 />} />
              <StatCard label="Conversões" value={clientMetrics.conversions.toString()} trend={15} icon={<ShoppingBag />} />
              <StatCard label="Cliques Únicos" value={clientMetrics.clicks.toLocaleString('pt-BR')} icon={<MousePointer />} />
            </div>

            <div className="bg-white p-6 md:p-8 rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
              <h3 className="font-black text-slate-900 uppercase tracking-widest text-[10px] mb-8 flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-indigo-600" /> Histórico de Performance
              </h3>
              <div className="h-[300px] w-full min-w-0 relative">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData}>
                    <defs>
                      <linearGradient id="colorSpend" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.15}/>
                        <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid vertical={false} stroke="#f1f5f9" strokeDasharray="3 3" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                    <YAxis hide />
                    <Tooltip contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}} />
                    <Area type="monotone" dataKey="spend" stroke="#4f46e5" fill="url(#colorSpend)" strokeWidth={4} name="Gasto" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-end justify-between">
                <h2 className="text-xl font-black text-slate-900 tracking-tight uppercase text-[12px] tracking-widest">Campanhas Ativas</h2>
                <div className="relative">
                   <input type="text" placeholder="Filtrar..." className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm min-w-[200px]" />
                   <Search className="w-4 h-4 text-slate-400 absolute left-3.5 top-1/2 -translate-y-1/2" />
                </div>
              </div>

              {selectedClient.campaigns.length === 0 ? (
                <div className="bg-white rounded-[32px] p-16 text-center border-2 border-slate-100 border-dashed">
                  <Database className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Aguardando dados da Meta Ads...</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                  {selectedClient.campaigns.map((campaign) => (
                    <div 
                      key={campaign.id} 
                      onClick={() => setSelectedCampaign(campaign)}
                      className="bg-white rounded-[32px] border border-slate-200 shadow-sm hover:shadow-xl hover:border-indigo-300 transition-all cursor-pointer group flex flex-col md:flex-row overflow-hidden"
                    >
                      <div className="w-full md:w-52 h-52 md:h-auto bg-slate-100 flex-shrink-0 relative overflow-hidden">
                        <img 
                          src={campaign.creative.url || 'https://via.placeholder.com/400'} 
                          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" 
                          alt={campaign.name} 
                        />
                        <div className="absolute top-4 left-4 bg-slate-900/90 text-white text-[8px] font-black uppercase px-2 py-1 rounded-lg tracking-widest">
                          {campaign.platform}
                        </div>
                      </div>

                      <div className="p-6 flex-1 flex flex-col">
                        <div className="flex-1">
                          <h3 className="font-black text-slate-900 text-sm group-hover:text-indigo-600 transition-colors line-clamp-1 leading-tight mb-2">
                            {campaign.name}
                          </h3>

                          <div className="flex flex-wrap gap-2 mb-4">
                            <div className="flex items-center gap-1 bg-indigo-50 text-indigo-600 px-2 py-1 rounded-md text-[9px] font-black uppercase border border-indigo-100/50">
                              <Target className="w-3 h-3" />
                              {campaign.objective}
                            </div>
                            <div className="flex items-center gap-1 bg-slate-100 text-slate-500 px-2 py-1 rounded-md text-[9px] font-black uppercase border border-slate-200/50">
                              <Users className="w-3 h-3" />
                              Público
                            </div>
                          </div>

                          <p className="text-[10px] text-slate-500 font-medium line-clamp-2 mb-4 italic">
                            "{campaign.audience || 'Segmentação automática'}"
                          </p>
                        </div>

                        <div className="grid grid-cols-3 gap-2 border-t border-slate-100 pt-4">
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">Investido</p>
                            <p className="font-black text-slate-900 text-xs truncate">R$ {campaign.metrics.spend.toLocaleString('pt-BR')}</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">ROAS</p>
                            <p className="font-black text-indigo-600 text-xs">{(campaign.metrics.conversionValue / (campaign.metrics.spend || 1)).toFixed(2)}x</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">CPA</p>
                            <p className="font-black text-slate-900 text-xs truncate">R$ {(campaign.metrics.spend / (campaign.metrics.conversions || 1)).toFixed(2)}</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {selectedCampaign && (
        <CampaignDetails campaign={selectedCampaign} onClose={() => setSelectedCampaign(null)} />
      )}

      {session.role === 'admin' && (
        <>
          <SettingsModal
            initialClient={null}
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            onSave={handleSaveAccount}
          />
          <AccessManagementModal
            clients={clients}
            isOpen={isAccessModalOpen}
            onClose={() => setIsAccessModalOpen(false)}
            onUpdateAccess={handleUpdateClientAccess}
          />
        </>
      )}
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { ArrowUpRight, ArrowDownRight, Minus, HelpCircle } from 'lucide-react';

interface StatCardProps {
  label: string;
  value: string;
  trend?: number; // percentage
  trendLabel?: string;
  icon?: React.ReactNode;
  neutral?: boolean;
  description?: string;
}

export const StatCard: React.FC<StatCardProps> = ({ label, value, trend, trendLabel, icon, neutral = false, description }) => {
  const [showTooltip, setShowTooltip] = useState(false);
  const isPositive = trend && trend > 0;
  const isNegative = trend && trend < 0;

  return (
    <div className="bg-white rounded-[24px] p-6 border border-slate-200 shadow-sm hover:shadow-md transition-all group relative">
      <div className="flex justify-between items-start mb-4">
        <div>
          <div className="flex items-center gap-1.5 mb-1">
            <p className="text-[10px] font-black text-slate-400 uppercase tracking-widest leading-none">{label}</p>
            {description && (
              <div className="relative">
                <button 
                  onMouseEnter={() => setShowTooltip(true)}
                  onMouseLeave={() => setShowTooltip(false)}
                  onClick={() => setShowTooltip(!showTooltip)}
                  className="text-slate-300 hover:text-indigo-500 transition-colors"
                >
                  <HelpCircle className="w-3 h-3" />
                </button>
                {showTooltip && (
                  <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-48 bg-slate-900 text-white text-[10px] p-3 rounded-xl shadow-xl z-50 animate-fade-in pointer-events-none font-medium leading-relaxed">
                    <div className="absolute border-8 border-transparent border-t-slate-900 -bottom-3.5 left-1/2 -translate-x-1/2"></div>
                    {description}
                  </div>
                )}
              </div>
            )}
          </div>
          <h3 className="text-2xl font-black text-slate-900 tracking-tight">{value}</h3>
        </div>
        {icon && <div className="p-2.5 bg-indigo-50 text-indigo-600 rounded-xl group-hover:scale-110 transition-transform">{icon}</div>}
      </div>

      {(trend !== undefined || neutral) && (
        <div className="flex items-center text-[11px] font-bold">
          {neutral ? (
            <span className="flex items-center text-slate-500 bg-slate-100 px-2 py-0.5 rounded-lg">
              <Minus className="w-3 h-3 mr-1" />
              0%
            </span>
          ) : isPositive ? (
            <span className="flex items-center text-emerald-700 bg-emerald-100 px-2 py-0.5 rounded-lg">
              <ArrowUpRight className="w-3 h-3 mr-1" />
              {trend}%
            </span>
          ) : (
            <span className="flex items-center text-rose-700 bg-rose-100 px-2 py-0.5 rounded-lg">
              <ArrowDownRight className="w-3 h-3 mr-1" />
              {Math.abs(trend || 0)}%
            </span>
          )}
          <span className="text-slate-400 ml-2 font-medium">{trendLabel || 'vs. anterior'}</span>
        </div>
      )}
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Sidebar } from './components/Sidebar.tsx';
import { StatCard } from './components/StatCard.tsx';
import { CampaignDetails } from './components/CampaignDetails.tsx';
import { SettingsModal } from './components/SettingsModal.tsx';
import { AccessManagementModal } from './components/AccessManagementModal.tsx';
import { DateRangePicker, DatePreset } from './components/DateRangePicker.tsx';
import { Login } from './components/Login.tsx';
import { Client, Campaign } from './types.ts';
import { Menu, Search, BarChart2, DollarSign, MousePointer, ShoppingBag, RefreshCw, TrendingUp, Loader2, PlusCircle, Database, AlertCircle, WifiOff, Clock, Target, Users } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { syncMetaAdsData, MetaAccountInfo } from './services/metaService.ts';
import { db } from './firebase.ts';
import { collection, onSnapshot, setDoc, doc, deleteDoc, query } from 'firebase/firestore';

interface UserSession {
  email: string;
  role: 'admin' | 'client';
  clientId?: string;
}

const sanitizeData = (obj: any): any => {
  if (Array.isArray(obj)) {
    return obj.map(sanitizeData);
  } else if (obj !== null && typeof obj === 'object') {
    return Object.fromEntries(
      Object.entries(obj)
        .filter(([_, v]) => v !== undefined)
        .map(([k, v]) => [k, sanitizeData(v)])
    );
  }
  return obj;
};

function App() {
  const [session, setSession] = useState<UserSession | null>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true);

  const [clients, setClients] = useState<Client[]>([]);
  const clientsRef = useRef<Client[]>([]);
  const [selectedClientId, setSelectedClientId] = useState<string>('');
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);

  const [datePreset, setDatePreset] = useState<DatePreset>('this_month');
  const [customRange, setCustomRange] = useState<{ since: string; until: string } | undefined>(undefined);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isAccessModalOpen, setIsAccessModalOpen] = useState(false);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const initialLoadDone = useRef(false);
  const isFirebaseAvailable = !!db;

  useEffect(() => {
    clientsRef.current = clients;
  }, [clients]);

  useEffect(() => {
    try {
      const savedAuth = localStorage.getItem('ads_manager_auth_v2');
      if (savedAuth) {
        setSession(JSON.parse(savedAuth));
      }
    } catch (e) {
      console.error("Erro ao ler auth local:", e);
    } finally {
      setIsAuthChecking(false);
    }
  }, []);

  useEffect(() => {
    if (!session || !isFirebaseAvailable) return;

    try {
      const q = query(collection(db, "clients"));
      const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const clientsData: Client[] = [];
        querySnapshot.forEach((doc) => {
          clientsData.push(doc.data() as Client);
        });

        setClients(clientsData);

        if (session.role === 'client' && session.clientId) {
          setSelectedClientId(session.clientId);
        } else {
          setSelectedClientId(currentId => {
            if (currentId && clientsData.some(c => c.id === currentId)) return currentId;
            return clientsData.length > 0 ? clientsData[0].id : '';
          });
        }
      }, (error) => {
        console.error("Erro no Firestore Snapshot:", error);
        setSyncError("Erro de conexão com o banco de dados.");
      });
      return () => unsubscribe();
    } catch (err) {
      console.error("Erro ao iniciar snapshot:", err);
      setSyncError("Erro crítico de inicialização.");
    }
  }, [session, isFirebaseAvailable]);

  const handleSyncData = useCallback(async (clientId: string, preset: DatePreset, range?: { since: string; until: string }) => {
    const clientToSync = clientsRef.current.find(c => c.id === clientId);
    if (!session || !clientToSync || isSyncing) return;

    setIsSyncing(true);
    setSyncError(null);

    try {
      if (clientToSync.adAccountId && clientToSync.accessToken) {
        const updatedClientData = await syncMetaAdsData(clientToSync, preset, range);
        if (isFirebaseAvailable) {
          const sanitized = sanitizeData(updatedClientData);
          await setDoc(doc(db, "clients", sanitized.id), sanitized, { merge: true });
        }
      }
    } catch (error: any) {
      console.error("Erro na sincronização:", error);
      setSyncError(`Falha na sincronização (${clientToSync.name}): ${error.message}`);
    } finally {
      setIsSyncing(false);
    }
  }, [session, isSyncing, isFirebaseAvailable]);

  useEffect(() => {
    if (session && selectedClientId) {
      if (initialLoadDone.current) {
        handleSyncData(selectedClientId, datePreset, customRange);
      } else {
        initialLoadDone.current = true;
      }
    }
  }, [datePreset, selectedClientId, session, customRange]);

  const handleDateSelect = (preset: DatePreset, range?: { since: string; until: string }) => {
    setDatePreset(preset);
    setCustomRange(range);
  };

  const handleLogin = (user: UserSession) => {
    setSession(user);
    localStorage.setItem('ads_manager_auth_v2', JSON.stringify(user));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja realmente sair?')) {
      setSession(null);
      localStorage.removeItem('ads_manager_auth_v2');
    }
  };

  const handleUpdateClientAccess = async (clientId: string, email: string, pass: string) => {
    if (!isFirebaseAvailable) return;
    const clientRef = doc(db, "clients", clientId);
    await setDoc(clientRef, { loginEmail: email, loginPassword: pass }, { merge: true });
  };

  const selectedClient = useMemo(() => {
    return clients.find(c => c.id === selectedClientId) || null;
  }, [clients, selectedClientId]);

  const clientMetrics = useMemo(() => {
    if (!selectedClient || !selectedClient.campaigns) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend || 0;
      acc.impressions += curr.metrics.impressions || 0;
      acc.clicks += curr.metrics.clicks || 0;
      acc.conversions += curr.metrics.conversions || 0;
      acc.revenue += curr.metrics.conversionValue || 0;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';

  const chartData = useMemo(() => {
    return [
      { name: 'Jan', spend: (clientMetrics.spend * 0.2), revenue: (clientMetrics.revenue * 0.15) },
      { name: 'Fev', spend: (clientMetrics.spend * 0.5), revenue: (clientMetrics.revenue * 0.45) },
      { name: 'Mar', spend: (clientMetrics.spend * 1.0), revenue: (clientMetrics.revenue * 1.0) },
    ];
  }, [clientMetrics]);

  const handleSaveAccount = async (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accountInfo, accessToken } = data;
    const clientId = `c_${accountInfo.id}`;

    const newClient: Client = {
      id: clientId,
      name: accountInfo.name,
      industry: 'Geral',
      avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
      adAccountId: accountInfo.id,
      accessToken: accessToken,
      lastSync: 'Conectado agora',
      campaigns: []
    };

    try {
      if (isFirebaseAvailable) {
        const sanitized = sanitizeData(newClient);
        await setDoc(doc(db, "clients", sanitized.id), sanitized, { merge: true });
        setSelectedClientId(clientId);
        setIsSettingsOpen(false);
        setTimeout(() => handleSyncData(clientId, datePreset, customRange), 500);
      }
    } catch (e: any) {
      alert("Erro ao salvar no banco de dados.");
    }
  };

  const handleDeleteClient = async (id: string) => {
    if (!window.confirm('Excluir este cliente e todos os dados salvos?')) return;
    try {
      if (isFirebaseAvailable) await deleteDoc(doc(db, "clients", id));
      if (selectedClientId === id) setSelectedClientId('');
    } catch (e) {
      console.error("Erro ao deletar:", e);
    }
  };

  if (isAuthChecking) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
      </div>
    );
  }

  if (!session) return <Login onLogin={handleLogin} />;

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={() => setIsSettingsOpen(true)}
        onOpenAccessManagement={() => setIsAccessModalOpen(true)}
        onDeleteClient={handleDeleteClient}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        onLogout={handleLogout}
        isAdmin={session.role === 'admin'}
      />

      <main className="flex-1 w-full lg:ml-64 transition-all duration-300 overflow-x-hidden relative">
        {syncError && (
          <div className="bg-rose-50 border-b border-rose-200 px-8 py-3 flex items-center gap-3 text-rose-700 text-xs font-bold animate-fade-in">
            <AlertCircle className="w-4 h-4" />
            {syncError}
            <button onClick={() => setSyncError(null)} className="ml-auto text-rose-400 hover:text-rose-600 font-black">X</button>
          </div>
        )}

        {!selectedClient && clients.length === 0 && (
          <div className="absolute inset-0 flex items-center justify-center bg-slate-50 z-10 p-8">
            <div className="text-center max-w-sm">
              <div className="bg-indigo-100 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6">
                <PlusCircle className="w-8 h-8 text-indigo-600" />
              </div>
              <h2 className="text-xl font-black text-slate-900 mb-2">Início do Dashboard</h2>
              <p className="text-slate-500 text-sm font-medium mb-8">Conecte sua primeira conta do Meta Ads para centralizar os dados.</p>
              {session.role === 'admin' && (
                <button onClick={() => setIsSettingsOpen(true)} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-black uppercase text-xs tracking-widest shadow-xl">
                  Conectar Conta
                </button>
              )}
            </div>
          </div>
        )}

        {selectedClient && (
          <div className="p-4 md:p-8 space-y-8 animate-fade-in pb-20">
            <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <div className="flex items-center gap-4 w-full md:w-auto">
                <button 
                  onClick={() => setIsSidebarOpen(true)}
                  className="lg:hidden p-2 bg-white border border-slate-200 rounded-xl text-slate-600"
                >
                  <Menu className="w-6 h-6" />
                </button>
                <div>
                  <div className="flex items-center gap-3">
                     <h1 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">{selectedClient.name}</h1>
                     <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-1 rounded border border-emerald-100 uppercase flex items-center gap-1">
                       <Database className="w-3 h-3" /> Online
                     </span>
                  </div>
                  <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                    ID: <span className="text-slate-900 font-bold">{selectedClient.adAccountId}</span> • Sync: <span className="text-indigo-600 font-bold">{selectedClient.lastSync}</span>
                  </p>
                </div>
              </div>

              <div className="flex flex-wrap gap-3 w-full md:w-auto">
                <button 
                  onClick={() => handleSyncData(selectedClientId, datePreset, customRange)}
                  disabled={isSyncing}
                  className={`flex-1 md:flex-none flex items-center justify-center gap-3 px-6 py-3 rounded-xl text-xs font-black uppercase transition-all shadow-lg active:scale-95 ${
                    isSyncing 
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200'
                  }`}
                >
                  <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                  {isSyncing ? 'Sincronizando...' : 'Sincronizar Agora'}
                </button>
                <DateRangePicker 
                  selected={datePreset} 
                  onSelect={handleDateSelect} 
                  initialCustomRange={customRange}
                />
              </div>
            </header>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
              <StatCard 
                label="Total Gasto" 
                value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} 
                trend={12} 
                icon={<DollarSign />} 
                description="Valor total investido no período selecionado."
              />
              <StatCard 
                label="ROAS Médio" 
                value={`${roas}x`} 
                trend={8} 
                icon={<BarChart2 />} 
                description="Retorno sobre investimento. Ex: 5x significa que para cada R$1 investido, retornou R$5 em vendas."
              />
              <StatCard 
                label="Conversões" 
                value={clientMetrics.conversions.toString()} 
                trend={15} 
                icon={<ShoppingBag />} 
                description="Quantidade de ações valiosas realizadas (Compras, Leads ou Mensagens)."
              />
              <StatCard 
                label="Cliques Únicos" 
                value={clientMetrics.clicks.toLocaleString('pt-BR')} 
                icon={<MousePointer />} 
                description="Quantidade de pessoas únicas que clicaram no seu anúncio."
              />
            </div>

            <div className="bg-white p-6 md:p-8 rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
              <h3 className="font-black text-slate-900 uppercase tracking-widest text-[10px] mb-8 flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-indigo-600" /> Histórico de Performance
              </h3>
              <div className="h-[300px] w-full min-w-0 relative">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData}>
                    <defs>
                      <linearGradient id="colorSpend" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.15}/>
                        <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid vertical={false} stroke="#f1f5f9" strokeDasharray="3 3" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                    <YAxis hide />
                    <Tooltip contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}} />
                    <Area type="monotone" dataKey="spend" stroke="#4f46e5" fill="url(#colorSpend)" strokeWidth={4} name="Gasto" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-end justify-between">
                <h2 className="text-xl font-black text-slate-900 tracking-tight uppercase text-[12px] tracking-widest">Campanhas Ativas</h2>
                <div className="relative">
                   <input type="text" placeholder="Filtrar..." className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm min-w-[200px]" />
                   <Search className="w-4 h-4 text-slate-400 absolute left-3.5 top-1/2 -translate-y-1/2" />
                </div>
              </div>

              {selectedClient.campaigns.length === 0 ? (
                <div className="bg-white rounded-[32px] p-16 text-center border-2 border-slate-100 border-dashed">
                  <Database className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Aguardando dados da Meta Ads...</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                  {selectedClient.campaigns.map((campaign) => (
                    <div 
                      key={campaign.id} 
                      onClick={() => setSelectedCampaign(campaign)}
                      className="bg-white rounded-[32px] border border-slate-200 shadow-sm hover:shadow-xl hover:border-indigo-300 transition-all cursor-pointer group flex flex-col md:flex-row overflow-hidden"
                    >
                      <div className="w-full md:w-52 h-52 md:h-auto bg-slate-100 flex-shrink-0 relative overflow-hidden">
                        <img 
                          src={campaign.creative.url || 'https://via.placeholder.com/400'} 
                          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" 
                          alt={campaign.name} 
                        />
                        <div className="absolute top-4 left-4 bg-slate-900/90 text-white text-[8px] font-black uppercase px-2 py-1 rounded-lg tracking-widest">
                          {campaign.platform}
                        </div>
                      </div>

                      <div className="p-6 flex-1 flex flex-col">
                        <div className="flex-1">
                          <h3 className="font-black text-slate-900 text-sm group-hover:text-indigo-600 transition-colors line-clamp-1 leading-tight mb-2">
                            {campaign.name}
                          </h3>

                          <div className="flex flex-wrap gap-2 mb-4">
                            <div className="flex items-center gap-1 bg-indigo-50 text-indigo-600 px-2 py-1 rounded-md text-[9px] font-black uppercase border border-indigo-100/50">
                              <Target className="w-3 h-3" />
                              {campaign.objective}
                            </div>
                            <div className="flex items-center gap-1 bg-slate-100 text-slate-500 px-2 py-1 rounded-md text-[9px] font-black uppercase border border-slate-200/50">
                              <Users className="w-3 h-3" />
                              Público
                            </div>
                          </div>

                          <p className="text-[10px] text-slate-500 font-medium line-clamp-2 mb-4 italic">
                            "{campaign.audience || 'Segmentação automática'}"
                          </p>
                        </div>

                        <div className="grid grid-cols-3 gap-2 border-t border-slate-100 pt-4">
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">Investido</p>
                            <p className="font-black text-slate-900 text-xs truncate">R$ {campaign.metrics.spend.toLocaleString('pt-BR')}</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">ROAS</p>
                            <p className="font-black text-indigo-600 text-xs">{(campaign.metrics.conversionValue / (campaign.metrics.spend || 1)).toFixed(2)}x</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">CPA</p>
                            <p className="font-black text-slate-900 text-xs truncate">R$ {(campaign.metrics.spend / (campaign.metrics.conversions || 1)).toFixed(2)}</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {selectedCampaign && (
        <CampaignDetails campaign={selectedCampaign} onClose={() => setSelectedCampaign(null)} />
      )}

      {session.role === 'admin' && (
        <>
          <SettingsModal
            initialClient={null}
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            onSave={handleSaveAccount}
          />
          <AccessManagementModal
            clients={clients}
            isOpen={isAccessModalOpen}
            onClose={() => setIsAccessModalOpen(false)}
            onUpdateAccess={handleUpdateClientAccess}
          />
        </>
      )}
    </div>
  );
}

export default App;

import React, { useState, useMemo } from 'react';
import { Campaign, AdSet, Ad } from '../types.ts';
import { X, Target, Activity, Sparkles, Loader2, Users, BarChart3, Layers, LayoutGrid, Play, MapPin, UserCheck, UserPlus, Users2, AlertCircle, Info, BookOpen } from 'lucide-react';
import { analyzeCampaignPerformance } from '../services/geminiService.ts';
import { BarChart as ReBarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip as ReTooltip, ResponsiveContainer, Legend } from 'recharts';
import ReactMarkdown from 'react-markdown';

interface CampaignDetailsProps {
  campaign: Campaign;
  onClose: () => void;
}

type Tab = 'overview' | 'adsets' | 'ads';

export const CampaignDetails: React.FC<CampaignDetailsProps> = ({ campaign, onClose }) => {
  const [activeTab, setActiveTab] = useState<Tab>('overview');
  const [analysis, setAnalysis] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const { metrics, adSets } = campaign;

  const costPerResult = metrics.messages && metrics.messages > 0 
    ? (metrics.spend / metrics.messages).toFixed(2) 
    : (metrics.conversions > 0 ? (metrics.spend / metrics.conversions).toFixed(2) : '0.00');

  const demographicChartData = useMemo(() => {
    const ageGroups = ['13-17', '18-24', '25-34', '35-44', '45-54', '55-64', '65+'];
    const hasData = metrics.demographics && metrics.demographics.length > 0;

    if (!hasData) return null;

    return ageGroups.map(age => {
      const male = metrics.demographics?.find(d => d.age === age && d.gender === 'male')?.results || 0;
      const female = metrics.demographics?.find(d => d.age === age && d.gender === 'female')?.results || 0;
      return { age, Homens: male, Mulheres: female };
    });
  }, [metrics.demographics]);

  const handleAnalyze = async () => {
    setLoading(true);
    const result = await analyzeCampaignPerformance(campaign);
    setAnalysis(result);
    setLoading(false);
  };

  const allAds: Ad[] = adSets?.flatMap(as => as.ads) || [];

  const renderAudienceDetails = (audienceStr: string) => {
    try {
      const t = JSON.parse(audienceStr);
      const items = [];
      if (t.targeting_id) items.push({ icon: <UserCheck className="w-3 h-3"/>, label: "Público", value: t.targeting_id });
      if (t.custom_audiences) items.push({ icon: <UserPlus className="w-3 h-3"/>, label: "Personalizado", value: "Sim" });
      const geo = t.geo_locations?.countries?.join(', ') || 'Global';
      items.push({ icon: <MapPin className="w-3 h-3"/>, label: "Local", value: geo });

      return (
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 mt-3">
          {items.map((item, idx) => (
            <div key={idx} className="flex items-center gap-2 bg-white border border-slate-100 px-3 py-2 rounded-xl">
               <span className="text-slate-400">{item.icon}</span>
               <span className="text-[10px] font-black text-slate-400 uppercase">{item.label}:</span>
               <span className="text-[11px] font-bold text-slate-700 truncate">{item.value}</span>
            </div>
          ))}
        </div>
      );
    } catch {
      return <p className="text-xs text-slate-500 mt-2 italic font-medium">{audienceStr}</p>;
    }
  };

  const glossaryItems = [
    { term: "ROAS", desc: "Retorno sobre o Investimento. 2.0x significa que para cada R$1,00 gasto, retornou R$2,00." },
    { term: "CTR", desc: "Taxa de cliques. Quantidade de pessoas que viram o anúncio e clicaram nele." },
    { term: "CPC", desc: "Custo por Clique. Média de quanto você paga por cada pessoa que clica." },
    { term: "CPM", desc: "Custo por Mil Impressões. Valor médio para mostrar seu anúncio 1.000 vezes." },
    { term: "CPA / Custo Res.", desc: "Custo por Ação ou Resultado. Média paga para cada conversão (Lead/Compra)." },
    { term: "Frequência", desc: "Média de quantas vezes uma única pessoa viu seu anúncio." }
  ];

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm z-[60] flex justify-end">
      <div className="w-full sm:max-w-5xl bg-slate-50 h-full shadow-2xl overflow-hidden animate-slide-in-right border-l border-slate-200 flex flex-col">

        <div className="p-4 md:p-6 bg-white border-b border-slate-200 shadow-sm flex-shrink-0">
          <div className="flex justify-between items-start mb-6">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-indigo-50 text-indigo-600 rounded-xl">
                 <Layers className="w-6 h-6" />
              </div>
              <div>
                <span className="text-[10px] uppercase tracking-widest text-slate-400 font-black">{campaign.platform} • {campaign.objective}</span>
                <h2 className="text-lg md:text-xl font-black text-slate-900 truncate">{campaign.name}</h2>
              </div>
            </div>
            <button onClick={onClose} className="p-2 hover:bg-slate-100 rounded-full text-slate-400">
              <X className="w-6 h-6" />
            </button>
          </div>

          <div className="flex gap-1 bg-slate-100 p-1 rounded-xl w-fit">
            <button onClick={() => setActiveTab('overview')} className={`px-4 py-2 rounded-lg text-xs font-black transition-all ${activeTab === 'overview' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Visão Geral</button>
            <button onClick={() => setActiveTab('adsets')} className={`px-4 py-2 rounded-lg text-xs font-black transition-all ${activeTab === 'adsets' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Conjuntos</button>
            <button onClick={() => setActiveTab('ads')} className={`px-4 py-2 rounded-lg text-xs font-black transition-all ${activeTab === 'ads' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500'}`}>Anúncios</button>
          </div>
        </div>

        <div className="flex-1 overflow-y-auto p-4 md:p-6 space-y-8 pb-32">
          {activeTab === 'overview' && (
            <div className="space-y-8 animate-fade-in">
              <div className="grid grid-cols-1 md:grid-cols-3 gap-4 md:gap-6">
                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm relative group">
                  <p className="text-[9px] font-black text-slate-400 uppercase mb-2 flex items-center gap-1">Investimento <Info className="w-2.5 h-2.5" /></p>
                  <p className="text-2xl font-black text-slate-900">R$ {metrics.spend.toLocaleString('pt-BR')}</p>
                </div>
                <div className="bg-indigo-600 p-6 rounded-3xl text-white shadow-xl shadow-indigo-100">
                  <p className="text-[9px] font-black text-indigo-200 uppercase mb-2">Resultados</p>
                  <p className="text-2xl font-black">{metrics.conversions || metrics.messages || 0}</p>
                </div>
                <div className="bg-white p-6 rounded-3xl border border-slate-200 shadow-sm">
                  <p className="text-[9px] font-black text-slate-400 uppercase mb-2">Custo Resultado</p>
                  <p className="text-2xl font-black text-slate-900">R$ {costPerResult}</p>
                </div>
              </div>

              <div className="bg-white p-6 md:p-8 rounded-3xl border border-slate-200 shadow-sm overflow-hidden">
                <h3 className="font-black text-slate-900 text-base uppercase tracking-tight mb-8">Público por Gênero e Idade</h3>
                {demographicChartData ? (
                  <div className="h-[300px] w-full min-w-0 relative">
                    <ResponsiveContainer width="100%" height="100%">
                      <ReBarChart data={demographicChartData}>
                        <CartesianGrid vertical={false} stroke="#f1f5f9" />
                        <XAxis dataKey="age" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                        <YAxis hide />
                        <ReTooltip cursor={{fill: '#f8fafc'}} contentStyle={{borderRadius: '16px', border: 'none', boxShadow: '0 10px 15px -3px rgb(0 0 0 / 0.1)'}} />
                        <Legend verticalAlign="bottom" iconType="circle" />
                        <Bar name="Homens" dataKey="Homens" fill="#6366f1" radius={[4, 4, 0, 0]} />
                        <Bar name="Mulheres" dataKey="Mulheres" fill="#2dd4bf" radius={[4, 4, 0, 0]} />
                      </ReBarChart>
                    </ResponsiveContainer>
                  </div>
                ) : (
                  <div className="h-[200px] flex flex-col items-center justify-center bg-slate-50 rounded-2xl border border-slate-100 border-dashed">
                    <AlertCircle className="w-8 h-8 text-slate-300 mb-2" />
                    <p className="text-[10px] font-black text-slate-300 uppercase">Sem dados demográficos</p>
                  </div>
                )}
              </div>

              <section className="bg-slate-900 rounded-[32px] p-6 md:p-8 text-white">
                <div className="flex justify-between items-center mb-6">
                  <div className="flex items-center gap-3">
                    <Sparkles className="w-5 h-5 text-indigo-400" />
                    <h3 className="text-xs font-black uppercase tracking-widest">Análise Estratégica IA</h3>
                  </div>
                  {!analysis && !loading && (
                    <button onClick={handleAnalyze} className="bg-indigo-600 text-white text-[10px] font-black px-4 py-2 rounded-lg uppercase hover:bg-indigo-500 transition-all">Gerar Análise</button>
                  )}
                </div>
                {loading ? (
                  <div className="flex items-center justify-center py-12">
                    <Loader2 className="w-8 h-8 animate-spin text-indigo-400" />
                  </div>
                ) : analysis && (
                  <div className="prose prose-sm prose-invert max-w-none text-slate-300">
                    <ReactMarkdown>{analysis}</ReactMarkdown>
                  </div>
                )}
              </section>

              {/* Glossário / Legenda de Siglas */}
              <div className="bg-slate-50 border border-slate-200 rounded-[32px] p-6 md:p-8">
                <div className="flex items-center gap-3 mb-6">
                   <div className="bg-indigo-100 p-2 rounded-xl text-indigo-600">
                      <BookOpen className="w-5 h-5" />
                   </div>
                   <h3 className="text-xs font-black uppercase tracking-widest text-slate-900">Legenda de Métricas</h3>
                </div>
                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                   {glossaryItems.map((item, idx) => (
                     <div key={idx} className="bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                        <p className="text-[10px] font-black text-indigo-600 uppercase mb-1">{item.term}</p>
                        <p className="text-[11px] text-slate-500 font-medium leading-relaxed">{item.desc}</p>
                     </div>
                   ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'adsets' && (
            <div className="space-y-6 animate-fade-in">
              {adSets?.map(adset => (
                <div key={adset.id} className="bg-white rounded-[28px] border border-slate-200 shadow-sm overflow-hidden">
                  <div className="p-5 bg-slate-50/50 border-b border-slate-100 flex justify-between items-center">
                    <div className="flex items-center gap-3">
                      <div className={`w-2 h-2 rounded-full ${adset.status === 'active' ? 'bg-emerald-500' : 'bg-slate-300'}`}></div>
                      <h4 className="font-black text-slate-900 text-sm">{adset.name}</h4>
                    </div>
                    <span className="text-[9px] font-black text-slate-400 uppercase">Budget: R$ {adset.budget}</span>
                  </div>
                  <div className="p-5">
                    {renderAudienceDetails(adset.audience)}
                    <div className="grid grid-cols-4 gap-4 mt-6">
                       <div>
                          <p className="text-[8px] font-black text-slate-400 uppercase">Investido</p>
                          <p className="text-xs font-black text-slate-800">R$ {adset.metrics.spend}</p>
                       </div>
                       <div>
                          <p className="text-[8px] font-black text-slate-400 uppercase">Conv.</p>
                          <p className="text-xs font-black text-slate-800">{adset.metrics.conversions || 0}</p>
                       </div>
                       <div>
                          <p className="text-[8px] font-black text-slate-400 uppercase">ROAS</p>
                          <p className="text-xs font-black text-indigo-600">{(adset.metrics.conversionValue / (adset.metrics.spend || 1)).toFixed(2)}x</p>
                       </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}

          {activeTab === 'ads' && (
            <div className="space-y-6 animate-fade-in">
              {allAds.map(ad => (
                <div key={ad.id} className="bg-white rounded-[32px] border border-slate-200 overflow-hidden shadow-sm flex flex-col md:flex-row group">
                  <div className="w-full md:w-64 h-64 md:h-auto bg-slate-100 flex-shrink-0 relative overflow-hidden">
                    <img src={ad.creative.url} className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-1000" />
                    <div className="absolute top-3 left-3 bg-slate-900/80 text-white text-[8px] font-black uppercase px-2 py-1 rounded-lg">ID: {ad.id}</div>
                  </div>
                  <div className="flex-1 p-6 flex flex-col justify-between">
                    <div>
                      <h5 className="font-black text-slate-900 text-base mb-1">{ad.name}</h5>
                      <p className="text-[10px] text-slate-400 font-bold mb-4">{ad.creative.headline}</p>
                      <div className="grid grid-cols-4 gap-4">
                        <div>
                          <p className="text-[8px] font-black text-slate-400 uppercase">Gasto</p>
                          <p className="text-xs font-black text-slate-800">R$ {ad.metrics.spend}</p>
                        </div>
                        <div>
                          <p className="text-[8px] font-black text-slate-400 uppercase">Cliques</p>
                          <p className="text-xs font-black text-slate-800">{ad.metrics.clicks}</p>
                        </div>
                        <div>
                          <p className="text-[8px] font-black text-slate-400 uppercase">CTR</p>
                          <p className="text-xs font-black text-slate-800">{((ad.metrics.clicks / (ad.metrics.impressions || 1)) * 100).toFixed(2)}%</p>
                        </div>
                        <div>
                          <p className="text-[8px] font-black text-slate-400 uppercase">CPM</p>
                          <p className="text-xs font-black text-slate-800">R$ {ad.metrics.cpm?.toFixed(2)}</p>
                        </div>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

import React, { useState, useMemo, useEffect, useRef, useCallback } from 'react';
import { Sidebar } from './components/Sidebar.tsx';
import { StatCard } from './components/StatCard.tsx';
import { CampaignDetails } from './components/CampaignDetails.tsx';
import { CreativePreviewModal } from './components/CreativePreviewModal.tsx';
import { SettingsModal } from './components/SettingsModal.tsx';
import { AccessManagementModal } from './components/AccessManagementModal.tsx';
import { DateRangePicker, DatePreset } from './components/DateRangePicker.tsx';
import { Login } from './components/Login.tsx';
import { Client, Campaign } from './types.ts';
import { Menu, Search, BarChart2, DollarSign, MousePointer, ShoppingBag, RefreshCw, TrendingUp, Loader2, PlusCircle, Database, AlertCircle, WifiOff, Clock, Target, Users } from 'lucide-react';
import { AreaChart, Area, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { syncMetaAdsData, MetaAccountInfo } from './services/metaService.ts';
import { db } from './firebase.ts';
import { collection, onSnapshot, setDoc, doc, deleteDoc, query } from 'firebase/firestore';

interface UserSession {
  email: string;
  role: 'admin' | 'client';
  clientId?: string;
}

const sanitizeData = (obj: any): any => {
  if (Array.isArray(obj)) {
    return obj.map(sanitizeData);
  } else if (obj !== null && typeof obj === 'object') {
    return Object.fromEntries(
      Object.entries(obj)
        .filter(([_, v]) => v !== undefined)
        .map(([k, v]) => [k, sanitizeData(v)])
    );
  }
  return obj;
};

function App() {
  const [session, setSession] = useState<UserSession | null>(null);
  const [isAuthChecking, setIsAuthChecking] = useState(true);

  const [clients, setClients] = useState<Client[]>([]);
  const clientsRef = useRef<Client[]>([]);
  const [selectedClientId, setSelectedClientId] = useState<string>('');
  const [selectedCampaign, setSelectedCampaign] = useState<Campaign | null>(null);
  const [previewCampaign, setPreviewCampaign] = useState<Campaign | null>(null);

  const [datePreset, setDatePreset] = useState<DatePreset>('this_month');
  const [customRange, setCustomRange] = useState<{ since: string; until: string } | undefined>(undefined);

  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [isSettingsOpen, setIsSettingsOpen] = useState(false);
  const [isAccessModalOpen, setIsAccessModalOpen] = useState(false);

  const [isSyncing, setIsSyncing] = useState(false);
  const [syncError, setSyncError] = useState<string | null>(null);

  const initialLoadDone = useRef(false);
  const isFirebaseAvailable = !!db;

  useEffect(() => {
    clientsRef.current = clients;
  }, [clients]);

  useEffect(() => {
    try {
      const savedAuth = localStorage.getItem('ads_manager_auth_v2');
      if (savedAuth) {
        setSession(JSON.parse(savedAuth));
      }
    } catch (e) {
      console.error("Erro ao ler auth local:", e);
    } finally {
      setIsAuthChecking(false);
    }
  }, []);

  useEffect(() => {
    if (!session || !isFirebaseAvailable) return;

    try {
      const q = query(collection(db, "clients"));
      const unsubscribe = onSnapshot(q, (querySnapshot) => {
        const clientsData: Client[] = [];
        querySnapshot.forEach((doc) => {
          clientsData.push(doc.data() as Client);
        });

        setClients(clientsData);

        if (session.role === 'client' && session.clientId) {
          setSelectedClientId(session.clientId);
        } else {
          setSelectedClientId(currentId => {
            if (currentId && clientsData.some(c => c.id === currentId)) return currentId;
            return clientsData.length > 0 ? clientsData[0].id : '';
          });
        }
      }, (error) => {
        console.error("Erro no Firestore Snapshot:", error);
        setSyncError("Erro de conexão com o banco de dados.");
      });
      return () => unsubscribe();
    } catch (err) {
      console.error("Erro ao iniciar snapshot:", err);
      setSyncError("Erro crítico de inicialização.");
    }
  }, [session, isFirebaseAvailable]);

  const handleSyncData = useCallback(async (clientId: string, preset: DatePreset, range?: { since: string; until: string }) => {
    const clientToSync = clientsRef.current.find(c => c.id === clientId);
    if (!session || !clientToSync || isSyncing) return;

    setIsSyncing(true);
    setSyncError(null);

    try {
      if (clientToSync.adAccountId && clientToSync.accessToken) {
        const updatedClientData = await syncMetaAdsData(clientToSync, preset, range);
        if (isFirebaseAvailable) {
          const sanitized = sanitizeData(updatedClientData);
          await setDoc(doc(db, "clients", sanitized.id), sanitized, { merge: true });
        }
      }
    } catch (error: any) {
      console.error("Erro na sincronização:", error);
      setSyncError(`Falha na sincronização (${clientToSync.name}): ${error.message}`);
    } finally {
      setIsSyncing(false);
    }
  }, [session, isSyncing, isFirebaseAvailable]);

  useEffect(() => {
    if (session && selectedClientId) {
      if (initialLoadDone.current) {
        handleSyncData(selectedClientId, datePreset, customRange);
      } else {
        initialLoadDone.current = true;
      }
    }
  }, [datePreset, selectedClientId, session, customRange]);

  const handleDateSelect = (preset: DatePreset, range?: { since: string; until: string }) => {
    setDatePreset(preset);
    setCustomRange(range);
  };

  const handleLogin = (user: UserSession) => {
    setSession(user);
    localStorage.setItem('ads_manager_auth_v2', JSON.stringify(user));
  };

  const handleLogout = () => {
    if (window.confirm('Deseja realmente sair?')) {
      setSession(null);
      localStorage.removeItem('ads_manager_auth_v2');
    }
  };

  const handleUpdateClientAccess = async (clientId: string, email: string, pass: string) => {
    if (!isFirebaseAvailable) return;
    const clientRef = doc(db, "clients", clientId);
    await setDoc(clientRef, { loginEmail: email, loginPassword: pass }, { merge: true });
  };

  const selectedClient = useMemo(() => {
    return clients.find(c => c.id === selectedClientId) || null;
  }, [clients, selectedClientId]);

  const clientMetrics = useMemo(() => {
    if (!selectedClient || !selectedClient.campaigns) return { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 };
    return selectedClient.campaigns.reduce((acc, curr) => {
      acc.spend += curr.metrics.spend || 0;
      acc.impressions += curr.metrics.impressions || 0;
      acc.clicks += curr.metrics.clicks || 0;
      acc.conversions += curr.metrics.conversions || 0;
      acc.revenue += curr.metrics.conversionValue || 0;
      return acc;
    }, { spend: 0, impressions: 0, clicks: 0, conversions: 0, revenue: 0 });
  }, [selectedClient]);

  const roas = clientMetrics.spend > 0 ? (clientMetrics.revenue / clientMetrics.spend).toFixed(2) : '0.00';

  const chartData = useMemo(() => {
    return [
      { name: 'Jan', spend: (clientMetrics.spend * 0.2), revenue: (clientMetrics.revenue * 0.15) },
      { name: 'Fev', spend: (clientMetrics.spend * 0.5), revenue: (clientMetrics.revenue * 0.45) },
      { name: 'Mar', spend: (clientMetrics.spend * 1.0), revenue: (clientMetrics.revenue * 1.0) },
    ];
  }, [clientMetrics]);

  const handleSaveAccount = async (data: { adAccountId: string; accessToken: string; accountInfo: MetaAccountInfo }) => {
    const { accountInfo, accessToken } = data;
    const clientId = `c_${accountInfo.id}`;

    const newClient: Client = {
      id: clientId,
      name: accountInfo.name,
      industry: 'Geral',
      avatar: `https://ui-avatars.com/api/?name=${encodeURIComponent(accountInfo.name)}&background=random`,
      adAccountId: accountInfo.id,
      accessToken: accessToken,
      lastSync: 'Conectado agora',
      campaigns: []
    };

    try {
      if (isFirebaseAvailable) {
        const sanitized = sanitizeData(newClient);
        await setDoc(doc(db, "clients", sanitized.id), sanitized, { merge: true });
        setSelectedClientId(clientId);
        setIsSettingsOpen(false);
        setTimeout(() => handleSyncData(clientId, datePreset, customRange), 500);
      }
    } catch (e: any) {
      alert("Erro ao salvar no banco de dados.");
    }
  };

  const handleDeleteClient = async (id: string) => {
    if (!window.confirm('Excluir este cliente e todos os dados salvos?')) return;
    try {
      if (isFirebaseAvailable) await deleteDoc(doc(db, "clients", id));
      if (selectedClientId === id) setSelectedClientId('');
    } catch (e) {
      console.error("Erro ao deletar:", e);
    }
  };

  const handleOpenDetails = (campaign: Campaign) => {
    setSelectedCampaign(campaign);
    setPreviewCampaign(null); // Fecha o preview ao abrir detalhes
  };

  if (isAuthChecking) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center">
        <Loader2 className="w-12 h-12 text-indigo-500 animate-spin" />
      </div>
    );
  }

  if (!session) return <Login onLogin={handleLogin} />;

  return (
    <div className="flex bg-slate-50 min-h-screen">
      <Sidebar 
        clients={clients} 
        selectedClientId={selectedClientId} 
        onSelectClient={setSelectedClientId} 
        onOpenSettings={() => setIsSettingsOpen(true)}
        onOpenAccessManagement={() => setIsAccessModalOpen(true)}
        onDeleteClient={handleDeleteClient}
        isOpen={isSidebarOpen}
        onClose={() => setIsSidebarOpen(false)}
        onLogout={handleLogout}
        isAdmin={session.role === 'admin'}
      />

      <main className="flex-1 w-full lg:ml-64 transition-all duration-300 overflow-x-hidden relative">
        {syncError && (
          <div className="bg-rose-50 border-b border-rose-200 px-8 py-3 flex items-center gap-3 text-rose-700 text-xs font-bold animate-fade-in">
            <AlertCircle className="w-4 h-4" />
            {syncError}
            <button onClick={() => setSyncError(null)} className="ml-auto text-rose-400 hover:text-rose-600 font-black">X</button>
          </div>
        )}

        {!selectedClient && clients.length === 0 && (
          <div className="absolute inset-0 flex items-center justify-center bg-slate-50 z-10 p-8">
            <div className="text-center max-w-sm">
              <div className="bg-indigo-100 w-16 h-16 rounded-2xl flex items-center justify-center mx-auto mb-6">
                <PlusCircle className="w-8 h-8 text-indigo-600" />
              </div>
              <h2 className="text-xl font-black text-slate-900 mb-2">Início do Dashboard</h2>
              <p className="text-slate-500 text-sm font-medium mb-8">Conecte sua primeira conta do Meta Ads para centralizar os dados.</p>
              {session.role === 'admin' && (
                <button onClick={() => setIsSettingsOpen(true)} className="w-full bg-indigo-600 text-white py-3 rounded-xl font-black uppercase text-xs tracking-widest shadow-xl">
                  Conectar Conta
                </button>
              )}
            </div>
          </div>
        )}

        {selectedClient && (
          <div className="p-4 md:p-8 space-y-8 animate-fade-in pb-20">
            <header className="flex flex-col md:flex-row justify-between items-start md:items-center gap-6">
              <div className="flex items-center gap-4 w-full md:w-auto">
                <button 
                  onClick={() => setIsSidebarOpen(true)}
                  className="lg:hidden p-2 bg-white border border-slate-200 rounded-xl text-slate-600"
                >
                  <Menu className="w-6 h-6" />
                </button>
                <div>
                  <div className="flex items-center gap-3">
                     <h1 className="text-xl md:text-2xl font-black text-slate-900 tracking-tight">{selectedClient.name}</h1>
                     <span className="text-[10px] font-black text-emerald-600 bg-emerald-50 px-2 py-1 rounded border border-emerald-100 uppercase flex items-center gap-1">
                       <Database className="w-3 h-3" /> Online
                     </span>
                  </div>
                  <p className="text-xs md:text-sm text-slate-500 font-medium mt-1">
                    ID: <span className="text-slate-900 font-bold">{selectedClient.adAccountId}</span> • Sync: <span className="text-indigo-600 font-bold">{selectedClient.lastSync}</span>
                  </p>
                </div>
              </div>

              <div className="flex flex-wrap gap-3 w-full md:w-auto">
                <button 
                  onClick={() => handleSyncData(selectedClientId, datePreset, customRange)}
                  disabled={isSyncing}
                  className={`flex-1 md:flex-none flex items-center justify-center gap-3 px-6 py-3 rounded-xl text-xs font-black uppercase transition-all shadow-lg active:scale-95 ${
                    isSyncing 
                      ? 'bg-slate-200 text-slate-400 cursor-not-allowed' 
                      : 'bg-indigo-600 text-white hover:bg-indigo-700 shadow-indigo-200'
                  }`}
                >
                  <RefreshCw className={`w-4 h-4 ${isSyncing ? 'animate-spin' : ''}`} />
                  {isSyncing ? 'Sincronizando...' : 'Sincronizar Agora'}
                </button>
                <DateRangePicker 
                  selected={datePreset} 
                  onSelect={handleDateSelect} 
                  initialCustomRange={customRange}
                />
              </div>
            </header>

            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4 md:gap-6">
              <StatCard 
                label="Total Gasto" 
                value={`R$ ${clientMetrics.spend.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`} 
                trend={12} 
                icon={<DollarSign />} 
                description="Valor total investido no período selecionado."
              />
              <StatCard 
                label="ROAS Médio" 
                value={`${roas}x`} 
                trend={8} 
                icon={<BarChart2 />} 
                description="Retorno sobre investimento. Ex: 5x significa que para cada R$1 investido, retornou R$5 em vendas."
              />
              <StatCard 
                label="Conversões" 
                value={clientMetrics.conversions.toString()} 
                trend={15} 
                icon={<ShoppingBag />} 
                description="Quantidade de ações valiosas realizadas (Compras, Leads ou Mensagens)."
              />
              <StatCard 
                label="Cliques Únicos" 
                value={clientMetrics.clicks.toLocaleString('pt-BR')} 
                icon={<MousePointer />} 
                description="Quantidade de pessoas únicas que clicaram no seu anúncio."
              />
            </div>

            <div className="bg-white p-6 md:p-8 rounded-[40px] border border-slate-200 shadow-sm overflow-hidden">
              <h3 className="font-black text-slate-900 uppercase tracking-widest text-[10px] mb-8 flex items-center gap-2">
                <TrendingUp className="w-4 h-4 text-indigo-600" /> Histórico de Performance
              </h3>
              <div className="h-[300px] w-full min-w-0 relative">
                <ResponsiveContainer width="100%" height="100%">
                  <AreaChart data={chartData}>
                    <defs>
                      <linearGradient id="colorSpend" x1="0" y1="0" x2="0" y2="1">
                        <stop offset="5%" stopColor="#4f46e5" stopOpacity={0.15}/>
                        <stop offset="95%" stopColor="#4f46e5" stopOpacity={0}/>
                      </linearGradient>
                    </defs>
                    <CartesianGrid vertical={false} stroke="#f1f5f9" strokeDasharray="3 3" />
                    <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 10, fontWeight: 700}} />
                    <YAxis hide />
                    <Tooltip contentStyle={{borderRadius: '24px', border: 'none', boxShadow: '0 20px 25px -5px rgb(0 0 0 / 0.1)'}} />
                    <Area type="monotone" dataKey="spend" stroke="#4f46e5" fill="url(#colorSpend)" strokeWidth={4} name="Gasto" />
                  </AreaChart>
                </ResponsiveContainer>
              </div>
            </div>

            <div className="space-y-6">
              <div className="flex items-end justify-between">
                <h2 className="text-xl font-black text-slate-900 tracking-tight uppercase text-[12px] tracking-widest">Campanhas Ativas</h2>
                <div className="relative">
                   <input type="text" placeholder="Filtrar..." className="pl-10 pr-4 py-2 bg-white border border-slate-200 rounded-xl text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none shadow-sm min-w-[200px]" />
                   <Search className="w-4 h-4 text-slate-400 absolute left-3.5 top-1/2 -translate-y-1/2" />
                </div>
              </div>

              {selectedClient.campaigns.length === 0 ? (
                <div className="bg-white rounded-[32px] p-16 text-center border-2 border-slate-100 border-dashed">
                  <Database className="w-12 h-12 text-slate-200 mx-auto mb-4" />
                  <p className="text-slate-400 font-black uppercase text-[10px] tracking-widest">Aguardando dados da Meta Ads...</p>
                </div>
              ) : (
                <div className="grid grid-cols-1 xl:grid-cols-2 gap-6">
                  {selectedClient.campaigns.map((campaign) => (
                    <div 
                      key={campaign.id} 
                      onClick={() => setPreviewCampaign(campaign)}
                      className="bg-white rounded-[32px] border border-slate-200 shadow-sm hover:shadow-xl hover:border-indigo-300 transition-all cursor-pointer group flex flex-col md:flex-row overflow-hidden"
                    >
                      <div className="w-full md:w-52 h-52 md:h-auto bg-slate-100 flex-shrink-0 relative overflow-hidden">
                        <img 
                          src={campaign.creative.url || 'https://via.placeholder.com/400'} 
                          className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700" 
                          alt={campaign.name} 
                        />
                        <div className="absolute top-4 left-4 bg-slate-900/90 text-white text-[8px] font-black uppercase px-2 py-1 rounded-lg tracking-widest">
                          {campaign.platform}
                        </div>
                      </div>

                      <div className="p-6 flex-1 flex flex-col">
                        <div className="flex-1">
                          <h3 className="font-black text-slate-900 text-sm group-hover:text-indigo-600 transition-colors line-clamp-1 leading-tight mb-2">
                            {campaign.name}
                          </h3>

                          <div className="flex flex-wrap gap-2 mb-4">
                            <div className="flex items-center gap-1 bg-indigo-50 text-indigo-600 px-2 py-1 rounded-md text-[9px] font-black uppercase border border-indigo-100/50">
                              <Target className="w-3 h-3" />
                              {campaign.objective}
                            </div>
                            <div className="flex items-center gap-1 bg-slate-100 text-slate-500 px-2 py-1 rounded-md text-[9px] font-black uppercase border border-slate-200/50">
                              <Users className="w-3 h-3" />
                              Público
                            </div>
                          </div>

                          <p className="text-[10px] text-slate-500 font-medium line-clamp-2 mb-4 italic">
                            "{campaign.audience || 'Segmentação automática'}"
                          </p>
                        </div>

                        <div className="grid grid-cols-3 gap-2 border-t border-slate-100 pt-4">
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">Investido</p>
                            <p className="font-black text-slate-900 text-xs truncate">R$ {campaign.metrics.spend.toLocaleString('pt-BR')}</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">ROAS</p>
                            <p className="font-black text-indigo-600 text-xs">{(campaign.metrics.conversionValue / (campaign.metrics.spend || 1)).toFixed(2)}x</p>
                          </div>
                          <div>
                            <p className="text-[8px] text-slate-400 uppercase font-black mb-1">CPA</p>
                            <p className="font-black text-slate-900 text-xs truncate">R$ {(campaign.metrics.spend / (campaign.metrics.conversions || 1)).toFixed(2)}</p>
                          </div>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        )}
      </main>

      {/* Modal de Detalhes da Campanha */}
      {selectedCampaign && (
        <CampaignDetails campaign={selectedCampaign} onClose={() => setSelectedCampaign(null)} />
      )}

      {/* Modal de Preview do Criativo */}
      {previewCampaign && (
        <CreativePreviewModal 
          campaign={previewCampaign} 
          onClose={() => setPreviewCampaign(null)}
          onOpenDetails={() => handleOpenDetails(previewCampaign)}
        />
      )}

      {session.role === 'admin' && (
        <>
          <SettingsModal
            initialClient={null}
            isOpen={isSettingsOpen}
            onClose={() => setIsSettingsOpen(false)}
            onSave={handleSaveAccount}
          />
          <AccessManagementModal
            clients={clients}
            isOpen={isAccessModalOpen}
            onClose={() => setIsAccessModalOpen(false)}
            onUpdateAccess={handleUpdateClientAccess}
          />
        </>
      )}
    </div>
  );
}

